      { name: '❤️ الصحة', value: `${player.health}/${player.max_health}`, inline: true },
      { name: '⚔️ الهجوم', value: `${player.attack}`, inline: true },
      { name: '🛡️ الدفاع', value: `${player.defense}`, inline: true },
      { name: '⚡ الطاقة', value: `${player.energy}/${player.max_energy}`, inline: true },
      { name: '💰 الذهب', value: `${player.gold.toLocaleString()}`, inline: true },
      { name: '💎 جوهر الظل', value: `${player.shadow_essence.toLocaleString()}`, inline: true },
      { name: '📊 الخبرة', value: `${player.xp}/${config.battle.xpPerLevel * player.level}`, inline: true },
      { name: '🔥 السلسلة اليومية', value: `${player.daily_streak || 0} يوم`, inline: true },
      { name: '🎮 ظلالك', value: `${shadows.length} مخلوق`, inline: true }
    )
    .setFooter({ text: '🌑 ممالك الظل • Shadow Realms', iconURL: 'https://cdn.discordapp.com/emojis/9851542345678.webp' })
    .setTimestamp();

  if (shadows.length > 0) {
    const mainShadow = shadows[0];
    embed.addFields({ name: `⭐ أفضل ظل: ${mainShadow.shadow_name}`, value: `مستوى ${mainShadow.level} | ${mainShadow.rarity} | ⚔️${mainShadow.attack} ❤️${mainShadow.hp}`, inline: false });
  }

  return embed;
}

function createShadowEmbed(shadow) {
  const rarityColors = { 'شائع': 0x888888, 'نادر': 0x00aaff, 'أسطوري': 0xffaa00, 'خرافي': 0xff44ff };
  const color = rarityColors[shadow.rarity] || 0x888888;

  const typeEmojis = { 'ناري': '🔥', 'مائي': '💧', 'ترابي': '🌍', 'هوائي': '💨', 'ظلامي': '🌑', 'نوراني': '✨' };
  const emoji = typeEmojis[shadow.shadow_type] || '👻';

  return createBaseEmbed(`${emoji} ${shadow.shadow_name}`, `مخلوق ظل ${shadow.rarity}`, color)
    .addFields(
      { name: '🔮 النوع', value: shadow.shadow_type, inline: true },
      { name: '⭐ الندرة', value: shadow.rarity, inline: true },
      { name: '📊 المستوى', value: `${shadow.level}`, inline: true },
      { name: '❤️ HP', value: `${shadow.hp}`, inline: true },
      { name: '⚔️ هجوم', value: `${shadow.attack}`, inline: true },
      { name: '🛡️ دفاع', value: `${shadow.defense}`, inline: true },
      { name: '💨 سرعة', value: `${shadow.speed}`, inline: true }
    );
}

function createShopEmbed(items) {
  const embed = createBaseEmbed('🏪 متجر الظل', 'اشتري الأسلحة والدروع والجرعات والمواد النادرة')
    .setColor(colors.gold);

  const categories = {};
  for (const item of items) {
    if (!categories[item.category]) categories[item.category] = [];
    categories[item.category].push(item);
  }

  for (const [category, catItems] of Object.entries(categories)) {
    const value = catItems.map(i => 
      `\`${i.id}\` **${i.name}** — ${i.price} 💰 | ${i.rarity}`
    ).join('\n');
    embed.addFields({ name: `📦 ${category}`, value, inline: false });
  }

  return embed;
}

function createGuildEmbed(guild, members) {
  const memberList = members.slice(0, 10).map(m => 
    `${m.role === 'زعيم' ? '👑' : m.role === 'نائب' ? '⚜️' : '▪️'} **${m.username}** - ${m.role}`
  ).join('\n');

  return createBaseEmbed(`🏰 ${guild.name}`, guild.description || 'قبيلة من نسّاجي الظل', colors.secondary)
    .addFields(
      { name: '👑 الزعيم', value: `<@${guild.owner_id}>`, inline: true },
      { name: '📊 المستوى', value: `${guild.level}`, inline: true },
      { name: '👥 الأعضاء', value: `${members.length}`, inline: true },
      { name: '📋 الأعضاء:', value: memberList || 'لا يوجد أعضاء', inline: false }
    );
}

function createBattleEmbed(player, enemy, playerHp, enemyHp, log) {
  const embed = createBaseEmbed('⚔️ معركة الظل', `**${player.username}** ⚔️ **${enemy.name}**`, colors.danger)
    .addFields(
      { name: `❤️ ${player.username}`, value: `${playerHp}/${player.health}`, inline: true },
      { name: `❤️ ${enemy.name}`, value: `${enemyHp}/${enemy.hp}`, inline: true },
      { name: '📜 سير المعركة', value: `\`\`\`${log.slice(0, 500)}\`\`\``, inline: false }
    );

  return embed;
}

function createActionRow(...buttons) {
  return new ActionRowBuilder().addComponents(buttons);
}

function createButton(customId, label, style = ButtonStyle.Primary, emoji = '', disabled = false) {
  return new ButtonBuilder()
    .setCustomId(customId)
    .setLabel(label)
    .setStyle(style)
    .setEmoji(emoji)
    .setDisabled(disabled);
}

function createLeaderboardEmbed(players, type = 'level') {
  const titles = { level: '📊 لوحة الشرف - المستوى', gold: '💰 لوحة الشرف - الذهب', shadow_essence: '💎 لوحة الشرف - جوهر الظل' };
  const title = titles[type] || titles.level;

  const medals = ['🥇', '🥈', '🥉'];
  const list = players.map((p, i) => {
    const medal = medals[i] || `${i + 1}.`;
    let stat = '';
    if (type === 'level') stat = `المستوى ${p.level} | XP: ${p.xp}`;
    else if (type === 'gold') stat = `${p.gold.toLocaleString()} 💰`;
    else if (type === 'shadow_essence') stat = `${p.shadow_essence.toLocaleString()} 💎`;
    return `${medal} **${p.username}** — ${stat}`;
  }).join('\n');

  return createBaseEmbed(title, list, colors.gold);
}

module.exports = {
  createBaseEmbed,
  createPlayerProfile,
  createShadowEmbed,
  createShopEmbed,
  createGuildEmbed,
  createBattleEmbed,
  createActionRow,
  createButton,
  createLeaderboardEmbed
};

const config = require('../config.json');

// Random integer between min and max (inclusive)
function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

// Random float between min and max
function randomFloat(min, max) {
  return Math.random() * (max - min) + min;
}

// Roll a dice (e.g., d6, d20)
function rollDice(sides = 6) {
  return randomInt(1, sides);
}

// Chance check (percentage 0-100)
function chance(percentage) {
  return Math.random() * 100 < percentage;
}

// Pick a random element from array
function randomPick(array) {
  return array[Math.floor(Math.random() * array.length)];
}

// Weighted random pick
function weightedRandom(items, weights) {
  const totalWeight = weights.reduce((a, b) => a + b, 0);
  let random = Math.random() * totalWeight;
  for (let i = 0; i < items.length; i++) {
    random -= weights[i];
    if (random <= 0) return items[i];
  }
  return items[items.length - 1];
}

// Calculate XP needed for level
function xpForLevel(level) {
  return config.battle.xpPerLevel * level;
}

// Calculate damage
function calculateDamage(attack, defense) {
  const base = Math.max(1, attack - defense * 0.5);
  const variance = randomFloat(0.8, 1.2);
  return Math.round(base * variance);
}

// Check if user can perform action (cooldown)
const cooldowns = new Map();

function checkCooldown(userId, action, seconds) {
  const key = `${userId}:${action}`;
  const now = Date.now();

  if (cooldowns.has(key)) {
    const expiresAt = cooldowns.get(key);
    if (now < expiresAt) {
      const remaining = Math.ceil((expiresAt - now) / 1000);
      return { onCooldown: true, remaining };
    }
  }

  cooldowns.set(key, now + seconds * 1000);
  return { onCooldown: false, remaining: 0 };
}

// Format time
function formatTime(seconds) {
  if (seconds < 60) return `${seconds} ثانية`;
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  if (mins < 60) return `${mins} دقيقة و ${secs} ثانية`;
  const hours = Math.floor(mins / 60);
  const remainingMins = mins % 60;
  return `${hours} ساعة و ${remainingMins} دقيقة`;
}

// Generate a random shadow creature name
const shadowNames = [
  'ظل الليل', 'شبح الظلام', 'عابر السبيل', 'زائر القمر',
  'حارس العتمة', 'طيف النسيان', 'همس الظل', 'راقص الظلال',
  'عين الجبَّار', 'لسعة الظلام', 'غول الرمال', 'عفريت النار',
  'ملك الظلال', 'أميرة الضباب', 'فارس القمر', 'ساحر العظام',
  'تنين الظل', 'ذئب العاصفة', 'عنقاء الظلام', 'ثعبان الجليد'
];

