// Enemy spawn chance based on player level
function getRandomEnemy(playerLevel) {
  const available = enemies.filter(e => e.minLevel <= playerLevel);
  // Give higher chance for enemies near player level
  const weighted = available.map(e => {
    const diff = Math.abs(e.minLevel - playerLevel);
    const weight = Math.max(1, 20 - diff);
    return { enemy: e, weight };
  });

  const totalWeight = weighted.reduce((a, b) => a + b.weight, 0);
  let rand = Math.random() * totalWeight;

  for (const { enemy, weight } of weighted) {
    rand -= weight;
    if (rand <= 0) return enemy;
  }

  return weighted[weighted.length - 1].enemy;
}

