async function registerCommands(client) {
  const commands = [];
  const commandFolders = ['economy', 'exploration', 'battle', 'collection', 'crafting', 'guild', 'info'];

  for (const folder of commandFolders) {
    const path = `./commands/${folder}`;
    try {
      const fs = require('fs');
      const commandFiles = fs.readdirSync(path).filter(file => file.endsWith('.js'));

      for (const file of commandFiles) {
        const command = require(`../commands/${folder}/${file}`);
        if ('data' in command && 'execute' in command) {
          commands.push(command.data.toJSON());
          console.log(chalk.cyan(` [✓] ${command.data.name}`));
        }
      }
    } catch (error) {
      console.error(chalk.red(` [✗] Error loading commands from ${folder}: ${error.message}`));
    }
  }

  try {
    const { REST, Routes } = require('discord.js');
    const rest = new REST({ version: '10' }).setToken(config.token);

    console.log(chalk.yellow(' جاري تسجيل أوامر السlash...'));

    // Register globally
    await rest.put(
      Routes.applicationCommands(client.user.id),
      { body: commands }
    );

    console.log(chalk.green(` تم تسجيل ${commands.length} أمر بنجاح!`));
  } catch (error) {
    console.error(chalk.red(` خطأ في تسجيل الأوامر: ${error.message}`));
  }
}

const { Events } = require('discord.js');
const chalk = require('chalk');

module.exports = {
  name: Events.InteractionCreate,
  async execute(interaction) {
    if (interaction.isChatInputCommand()) {
      const command = interaction.client.commands.get(interaction.commandName);

      if (!command) {
        console.error(chalk.red(` الأمر ${interaction.commandName} غير موجود`));
        return;
      }

      try {
        console.log(chalk.blue(` [CMD] ${interaction.user.tag} → /${interaction.commandName}`));
        await command.execute(interaction);
      } catch (error) {
        console.error(chalk.red(` [ERROR] ${interaction.commandName}: ${error.message}`));
        console.error(error);

        const errorMessage = '❌ حدث خطأ أثناء تنفيذ الأمر. حاول مرة أخرى.';

        if (interaction.replied || interaction.deferred) {
          await interaction.followUp({ content: errorMessage, ephemeral: true });
        } else {
          await interaction.reply({ content: errorMessage, ephemeral: true });
        }
      }
    } else if (interaction.isButton()) {
      // Handle button interactions
      const [action, ...args] = interaction.customId.split(':');

      try {
        console.log(chalk.cyan(` [BTN] ${interaction.user.tag} → ${action}`));

        switch (action) {
          case 'hunt_attack':
            await handleHuntAttack(interaction, args);
            break;
          case 'hunt_flee':
            await handleHuntFlee(interaction);
            break;
          case 'explore':
            await handleExplore(interaction);
            break;
          case 'profile_refresh':
            await handleProfileRefresh(interaction);
            break;
          default:
            await interaction.reply({ content: '❌ زر غير معروف.', ephemeral: true });
        }
      } catch (error) {
        console.error(chalk.red(` [BTN_ERROR] ${error.message}`));
        if (!interaction.replied && !interaction.deferred) {
          await interaction.reply({ content: '❌ حدث خطأ.', ephemeral: true });
        }
      }
    }
  }
};

async function handleHuntAttack(interaction, args) {
  const { getPlayer, updatePlayer } = require('../database/db');
  const { calculateDamage, randomInt, chance } = require('../utils/helpers');
  const { createBattleEmbed } = require('../utils/embeds');

  const player = getPlayer(interaction.user.id, interaction.user.username);
  const enemyData = JSON.parse(decodeURIComponent(args[0]));

  let playerHp = parseInt(args[1]) || player.health;
  let enemyHp = parseInt(args[2]) || enemyData.hp;

  // Player attacks
  const playerDamage = calculateDamage(player.attack, enemyData.defense);
  enemyHp -= playerDamage;

  let log = `⚔️ ${interaction.user.username} يهاجم ${enemyData.name} ويسبب ${playerDamage} ضرر!\n`;

  if (enemyHp <= 0) {
    // Victory!
    const xpReward = enemyData.xpReward + randomInt(0, 10);
    const goldReward = enemyData.goldReward + randomInt(0, 20);

    updatePlayer(interaction.user.id, {
      xp: player.xp + xpReward,
      gold: player.gold + goldReward,
      health: playerHp
    });

    // Level up check
    const { xpForLevel } = require('../utils/helpers');
    const needed = xpForLevel(player.level);
    if (player.xp + xpReward >= needed) {
      updatePlayer(interaction.user.id, {
        level: player.level + 1,
        xp: (player.xp + xpReward) - needed,
        max_health: player.max_health + 10,
        health: player.max_health + 10,
        attack: player.attack + 2,
        defense: player.defense + 1,
        max_energy: player.max_energy + 5,
        energy: player.max_energy + 5
      });
      log += `\n🎉 **ارتقيت إلى المستوى ${player.level + 1}!**\n`;
    }

    log += `\n✨ انتصرت على ${enemyData.name}!\n`;
    log += `💰 حصلت على ${goldReward} ذهب\n`;
    log += `📊 حصلت على ${xpReward} خبرة\n`;

    // Chance to drop an item
    if (chance(15)) {
      const { addItem, generateShadowName, generateShadowType, generateRarity } = require('../utils/helpers');
      const shadowName = generateShadowName();
      const shadowType = generateShadowType();
      const rarity = generateRarity();
      addItem(interaction.user.id, 'material', shadowName, rarity);
      log += `\n🎁 سقط من ${enemyData.name}: **${shadowName}** (${rarity})!\n`;
    }

    const embed = createBattleEmbed(player, enemyData, playerHp, 0, log);
    await interaction.update({ embeds: [embed], components: [] });
    return;
  }

  // Enemy attacks back
  const enemyDamage = calculateDamage(enemyData.attack, player.defense);
  playerHp -= enemyDamage;
  log += `💥 ${enemyData.name} يهاجمك ويسبب ${enemyDamage} ضرر!\n`;

  if (playerHp <= 0) {
    playerHp = 1; // Don't let player die, just lose some gold
    const lostGold = Math.min(player.gold, randomInt(10, 50));
    updatePlayer(interaction.user.id, {
      gold: player.gold - lostGold,
      health: playerHp
    });
    log += `\n💀 خسرت المعركة! خسرت ${lostGold} ذهب...\n`;
  }

  const embed = createBattleEmbed(player, enemyData, playerHp, enemyHp, log);
  const { ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');

  const row = new ActionRowBuilder()
    .addComponents(
      new ButtonBuilder()
        .setCustomId(`hunt_attack:${encodeURIComponent(JSON.stringify(enemyData))}:${playerHp}:${enemyHp}`)
        .setLabel('⚔️ هجوم')
        .setStyle(ButtonStyle.Danger),
      new ButtonBuilder()
        .setCustomId('hunt_flee')
        .setLabel('🏃 فرار')
        .setStyle(ButtonStyle.Secondary)
    );

  await interaction.update({ embeds: [embed], components: [row] });
}

