async function handleExplore(interaction) {
  const { getPlayer, updatePlayer, addItem } = require('../database/db');
  const { explorationEvents, randomInt, chance, randomPick } = require('../utils/helpers');
  const { createBaseEmbed } = require('../utils/embeds');

  const player = getPlayer(interaction.user.id, interaction.user.username);

  if (player.energy < 10) {
    const embed = createBaseEmbed('⚡ طاقة منخفضة', 'ليس لديك طاقة كافية للاستكشاف! انتظر حتى تستعيد طاقتك.', 0xff4444);
    await interaction.update({ embeds: [embed], components: [] });
    return;
  }

  const event = randomPick(explorationEvents);
  const success = chance(event.successChance);

  updatePlayer(interaction.user.id, {
    energy: player.energy - 10
  });

  if (success) {
    const goldReward = randomInt(event.rewards.gold.min, event.rewards.gold.max);
    const xpReward = randomInt(event.rewards.xp.min, event.rewards.xp.max);

    updatePlayer(interaction.user.id, {
      gold: player.gold + goldReward,
      xp: player.xp + xpReward
    });

    let description = `📍 **${event.name}**\n${event.description}\n\n✅ نجحت في الاستكشاف!\n💰 +${goldReward} ذهب\n📊 +${xpReward} خبرة`;

    // Random loot
    if (chance(40)) {
      const loot = randomPick(event.loot);
      addItem(interaction.user.id, 'material', loot, 'شائع');
      description += `\n🎁 وجدت: **${loot}**`;
    }

    const embed = createBaseEmbed('🌍 استكشاف', description, 0x00ff88);
    await interaction.update({ embeds: [embed], components: [] });
  } else {
    const damage = randomInt(5, 20);
    const newHealth = Math.max(1, player.health - damage);
    updatePlayer(interaction.user.id, { health: newHealth });

    const embed = createBaseEmbed('🌍 استكشاف - فشل', `📍 **${event.name}**\n${event.description}\n\n❌ فشلت في الاستكشاف!\n💥 تعرضت لـ ${damage} ضرر\n❤️ صحتك الآن: ${newHealth}`, 0xff4444);
    await interaction.update({ embeds: [embed], components: [] });
  }
}

