const { SlashCommandBuilder, ActionRowBuilder, StringSelectMenuBuilder, StringSelectMenuOptionBuilder } = require('discord.js');
const { shopItems } = require('../../utils/helpers');
const { createShopEmbed } = require('../../utils/embeds');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('shop')
    .setDescription('🏪 متجر الظل - اشتري الأسلحة والدروع والجرعات'),

  async execute(interaction) {
    const categories = [...new Set(shopItems.map(i => i.category))];

    const embed = createBaseEmbed('🏪 متجر الظل', 'اختر فئة من القائمة أدناه لرؤية المنتجات', 0xffd700);

    const select = new StringSelectMenuBuilder()
      .setCustomId('shop_select')
      .setPlaceholder('📌 اختر فئة...')
      .addOptions(
        categories.map(cat => 
          new StringSelectMenuOptionBuilder()
            .setLabel(cat)
            .setValue(cat)
            .setDescription(`عرض ${cat} المتاحة`)
            .setEmoji(cat === 'أسلحة' ? '⚔️' : cat === 'دروع' ? '🛡️' : cat === 'جرعات' ? '🧪' : cat === 'مواد' ? '💎' : '🔮')
        )
      );

    const row = new ActionRowBuilder().addComponents(select);

    await interaction.reply({ embeds: [embed], components: [row] });

    // Handle selection
    const filter = i => i.customId === 'shop_select' && i.user.id === interaction.user.id;
    try {
      const selection = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });

      const category = selection.values[0];
      const items = shopItems.filter(i => i.category === category);

      const catEmbed = createBaseEmbed(`🏪 ${category}`, 'اختر منتجاً للشراء', 0xffd700);

      const itemList = items.map((item, index) => 
        `\`${index + 1}\` **${item.name}**\n` +
        `   ⭐ ${item.rarity} | 💰 ${item.price.toLocaleString()} ذهب\n` +
        `   ${item.stats ? `📊 ${Object.entries(item.stats).map(([k, v]) => `${k === 'attack' ? '⚔️' : k === 'defense' ? '🛡️' : k === 'health' ? '❤️' : k === 'speed' ? '💨' : k === 'heal' ? '💚' : k === 'energy' ? '⚡' : k === 'essence' ? '💎' : '📊'} ${k}: +${v}`).join(' | ')}` : ''}`
      ).join('\n\n');

      catEmbed.setDescription(itemList);
      catEmbed.setFooter({ text: 'استخدم /buy [اسم المنتج] للشراء' });

      await selection.update({ embeds: [catEmbed], components: [] });
    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        const timeoutEmbed = createBaseEmbed('⏰ انتهى الوقت', 'لم تختر أي فئة.', 0x888888);
        await interaction.editReply({ embeds: [timeoutEmbed], components: [] });
      }
    }
  }
};

const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, addItem } = require('../../database/db');
const { shopItems } = require('../../utils/helpers');
const { createBaseEmbed } = require('../../utils/embeds');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('buy')
    .setDescription('🛒 شراء منتج من متجر الظل')
    .addStringOption(option =>
      option.setName('product')
        .setDescription('اسم المنتج أو معرفه')
        .setRequired(true)
        .setAutocomplete(true)
    )
    .addIntegerOption(option =>
      option.setName('quantity')
        .setDescription('الكمية (الافتراضي: 1)')
        .setRequired(false)
        .setMinValue(1)
        .setMaxValue(99)
    ),

  async execute(interaction) {
    const productName = interaction.options.getString('product');
    const quantity = interaction.options.getInteger('quantity') || 1;

    // Find the product
    const product = shopItems.find(i => 
      i.name === productName || i.id === productName || productName.includes(i.name)
    );

    if (!product) {
      const embed = createBaseEmbed('❌ منتج غير موجود', 'لم أجد هذا المنتج. استخدم `/shop` لعرض المنتجات المتاحة.', 0xff4444);
      return interaction.reply({ embeds: [embed], ephemeral: true });
    }

    const player = getPlayer(interaction.user.id, interaction.user.username);
    const totalCost = product.price * quantity;

    if (player.gold < totalCost) {
      const embed = createBaseEmbed('❌ رصيد غير كافٍ', 
        `تحتاج ${totalCost.toLocaleString()} ذهب لشراء ${quantity}x ${product.name}.\n` +
        `لديك فقط ${player.gold.toLocaleString()} ذهب.`, 0xff4444);
      return interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Process purchase
    updatePlayer(interaction.user.id, { gold: player.gold - totalCost });

    const statsStr = JSON.stringify(product.stats || {});
    addItem(interaction.user.id, product.type, product.name, product.rarity, quantity, statsStr);

    const embed = createBaseEmbed('✅ تم الشراء بنجاح!', 
      `**${quantity}x ${product.name}**\n` +
      `⭐ الندرة: ${product.rarity}\n` +
      `💰 التكلفة: ${totalCost.toLocaleString()} ذهب\n` +
      `📦 تمت إضافة المشتريات إلى مخزونك.`,
      0x00ff88
    );

    await interaction.reply({ embeds: [embed] });
  }
};

