const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, getInventory, addItem, removeItem, db } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');

const activeTrades = new Map();

module.exports = {
  data: new SlashCommandBuilder()
    .setName('trade')
    .setDescription('🤝 تبادل العناصر والذهب مع لاعب آخر')
    .addUserOption(option =>
      option.setName('partner')
        .setDescription('اللاعب الذي تريد التبادل معه')
        .setRequired(true)
    )
    .addIntegerOption(option =>
      option.setName('gold')
        .setDescription('كمية الذهب التي تريد إعطاءها')
        .setRequired(false)
        .setMinValue(1)
    ),

  async execute(interaction) {
    const partner = interaction.options.getUser('partner');
    const gold = interaction.options.getInteger('gold') || 0;

    if (partner.id === interaction.user.id) {
      return interaction.reply({ content: '❌ لا يمكنك التبادل مع نفسك!', ephemeral: true });
    }

    if (partner.bot) {
      return interaction.reply({ content: '❌ لا يمكنك التبادل مع البوتات!', ephemeral: true });
    }

    const player = getPlayer(interaction.user.id, interaction.user.username);

    if (gold > 0 && player.gold < gold) {
      return interaction.reply({ content: `❌ ليس لديك ${gold} ذهب!`, ephemeral: true });
    }

    // Check for existing trade
    if (activeTrades.has(interaction.user.id) || activeTrades.has(partner.id)) {
      return interaction.reply({ content: '❌ أحد اللاعبين مشغول بالفعل في تبادل!', ephemeral: true });
    }

    const tradeId = `${interaction.user.id}-${partner.id}-${Date.now()}`;
    activeTrades.set(interaction.user.id, tradeId);
    activeTrades.set(partner.id, tradeId);

    const embed = createBaseEmbed('🤝 طلب تبادل',
      `**${interaction.user.username}** يريد التبادل مع **${partner.username}**\n\n` +
      `💰 سيعطي: ${gold > 0 ? `${gold} ذهب` : 'لا شيء'}\n` +
      `\nعلى ${partner.username} الرد خلال 60 ثانية`,
      0x00aaff
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder()
          .setCustomId(`trade_accept:${interaction.user.id}:${gold}`)
          .setLabel('✅ قبول')
          .setStyle(ButtonStyle.Success),
        new ButtonBuilder()
          .setCustomId(`trade_decline:${interaction.user.id}`)
          .setLabel('❌ رفض')
          .setStyle(ButtonStyle.Danger)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    // Clean up after timeout
    setTimeout(() => {
      activeTrades.delete(interaction.user.id);
      activeTrades.delete(partner.id);
    }, 60000);
  }
};

