module.exports = {
  data: new SlashCommandBuilder()
    .setName('craft')
    .setDescription('🔨 صياغة عناصر جديدة باستخدام المواد التي جمعتها'),

  async execute(interaction) {
    const categories = Object.keys(recipes);

    const select = new StringSelectMenuBuilder()
      .setCustomId('craft_select')
      .setPlaceholder('🔨 اختر فئة للصياغة...')
      .addOptions(
        categories.map(cat => 
          new StringSelectMenuOptionBuilder()
            .setLabel(cat === 'weapon' ? 'أسلحة' : cat === 'potion' ? 'جرعات' : 'مواد')
            .setValue(cat)
            .setDescription(`صياغة ${cat === 'weapon' ? 'أسلحة' : cat === 'potion' ? 'جرعات' : 'مواد'} متطورة`)
            .setEmoji(cat === 'weapon' ? '⚔️' : cat === 'potion' ? '🧪' : '💎')
        )
      );

    const row = new ActionRowBuilder().addComponents(select);

    const embed = createBaseEmbed('🔨 ورشة الصياغة', 
      'اختر فئة لترى الوصفات المتاحة للصياغة.\n\n' +
      '**المواد المتوفرة لديك ستظهر تلقائياً.**',
      0xff8800
    );

    await interaction.reply({ embeds: [embed], components: [row] });

    // Handle selection
    const filter = i => i.customId === 'craft_select' && i.user.id === interaction.user.id;
    try {
      const selection = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });
      const category = selection.values[0];
      const categoryRecipes = recipes[category];

      const inventory = getInventory(interaction.user.id);
      const inventoryMap = {};
      for (const item of inventory) {
        inventoryMap[item.item_name] = item;
      }

      let description = '';
      for (const recipe of categoryRecipes) {
        const canCraft = recipe.required.every(req => {
          const inv = inventoryMap[req.item];
          return inv && inv.quantity >= req.qty;
        });

        description += `${canCraft ? '✅' : '❌'} **${recipe.result.name}** (${recipe.result.rarity})\n`;
        description += `   المواد: ${recipe.required.map(r => `${r.item} ×${r.qty} ${(inventoryMap[r.item]?.quantity || 0) >= r.qty ? '✅' : `❌(${inventoryMap[r.item]?.quantity || 0})`}`).join(', ')}\n`;
        description += `   النتيجة: ${recipe.result.name} ⭐${recipe.result.rarity}\n\n`;
      }

      const craftEmbed = createBaseEmbed(`🔨 ${category === 'weapon' ? 'أسلحة' : category === 'potion' ? 'جرعات' : 'مواد'}`, description, 0xff8800);
      craftEmbed.setFooter({ text: 'استخدم /craft [اسم الوصفة] للصياغة' });

      await selection.update({ embeds: [craftEmbed], components: [] });
    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        // Ignore timeout
      }
    }
  }
};

const { SlashCommandBuilder } = require('discord.js');
