const { Client, GatewayIntentBits, Collection } = require('discord.js');
const fs = require('fs');
const path = require('path');
const chalk = require('chalk');
const config = require('./config.json');

// Validate config
if (config.token === 'YOUR_BOT_TOKEN_HERE') {
  console.error(chalk.red('✗ يرجى وضع التوكن الخاص بالبوت في ملف config.json'));
  console.error(chalk.yellow('  اذهب إلى https://discord.com/developers/applications وأنشئ تطبيقاً'));
  process.exit(1);
}

// Create client
const client = new Client({
  intents: [
    GatewayIntentBits.Guilds,
    GatewayIntentBits.GuildMessages,
    GatewayIntentBits.MessageContent,
    GatewayIntentBits.GuildMembers
  ]
});

// Commands collection
client.commands = new Collection();
client.config = config;

// Load commands
const commandFolders = ['economy', 'exploration', 'battle', 'collection', 'crafting', 'guild', 'info'];

console.log(chalk.cyan('\n📂 جاري تحميل الأوامر...\n'));

for (const folder of commandFolders) {
  const commandsPath = path.join(__dirname, 'commands', folder);
  if (!fs.existsSync(commandsPath)) continue;

  const commandFiles = fs.readdirSync(commandsPath).filter(file => file.endsWith('.js'));

  for (const file of commandFiles) {
    const filePath = path.join(commandsPath, file);
    const command = require(filePath);

    if ('data' in command && 'execute' in command) {
      client.commands.set(command.data.name, command);
      console.log(chalk.green(`  ✓ ${command.data.name}`));
    } else {
      console.log(chalk.yellow(`  ⚠ ${file} مفقود execute أو data`));
    }
  }
}

// Load events
console.log(chalk.cyan('\n📂 جاري تحميل الأحداث...\n'));

const eventsPath = path.join(__dirname, 'events');
const eventFiles = fs.readdirSync(eventsPath).filter(file => file.endsWith('.js'));

for (const file of eventFiles) {
  const filePath = path.join(eventsPath, file);
  const event = require(filePath);

  if (event.once) {
    client.once(event.name, (...args) => event.execute(...args));
  } else {
    client.on(event.name, (...args) => event.execute(...args));
  }

  console.log(chalk.green(`  ✓ ${event.name}`));
}

// Handle prefix commands (optional, for bots with message content)
client.on('messageCreate', async (message) => {
  if (message.author.bot) return;
  if (!message.content.startsWith(config.prefix)) return;

  const args = message.content.slice(config.prefix.length).trim().split(/ +/);
  const commandName = args.shift()?.toLowerCase();

  if (!commandName) return;

  // Simple prefix commands
  const prefixCommands = {
    'profile': async (msg) => {
      const { getPlayer, getShadows, getInventory } = require('./database/db');
      const { createPlayerProfile } = require('./utils/embeds');
      const player = getPlayer(msg.author.id, msg.author.username);
      const shadows = getShadows(msg.author.id);
      const inventory = getInventory(msg.author.id);
      const embed = createPlayerProfile(player, shadows, inventory);
      await msg.reply({ embeds: [embed] });
    },
    'daily': async (msg) => {
      // Redirect to slash command logic
      await msg.reply('📌 استخدم `/daily` للحصول على مكافأتك اليومية!');
    },
    'help': async (msg) => {
      const helpCmd = client.commands.get('help');
      if (helpCmd) {
        // Simulate interaction
        const mockInteraction = {
          reply: (data) => msg.reply(data),
          user: msg.author,
          guild: msg.guild,
          channel: msg.channel
        };
        // Actually just send the help text
        const embed = require('./utils/embeds').createBaseEmbed('🌑 ممالك الظل • دليل الأوامر',
          'استخدم الأوامر بالـ `/` للتفاعل مع البوت:\n\n' +
          '👤 `/profile` - ملفك الشخصي\n' +
          '💰 `/daily` - المكافأة اليومية\n' +
          '💰 `/balance` - رصيدك\n' +
          '🏪 `/shop` - المتجر\n' +
          '🌍 `/explore` - استكشاف\n' +
          '⚔️ `/hunt` - صيد\n' +
          '🤺 `/duel` - مبارزة\n' +
          '🏰 `/guild` - القبائل\n' +
          '🎒 `/inventory` - المخزون\n' +
          '📊 `/leaderboard` - لوحة الشرف',
          config.colors.primary
        );
        await msg.reply({ embeds: [embed] });
      }
    }
  };

  const cmd = prefixCommands[commandName];
  if (cmd) {
    try {
      await cmd(message);
    } catch (error) {
      console.error(chalk.red(`[PREFIX ERROR] ${error.message}`));
      await message.reply('❌ حدث خطأ.');
    }
  }
});

// Handle unhandled errors
process.on('unhandledRejection', (error) => {
  console.error(chalk.red('❌ خطأ غير متوقع:'), error.message);
});

process.on('uncaughtException', (error) => {
  console.error(chalk.red('❌ استثناء غير متوقع:'), error.message);
});

// Login
console.log(chalk.magenta('\n🌑 جاري تشغيل ممالك الظل...\n'));

client.login(config.token)
  .then(() => {
    console.log(chalk.green('✓ تم الاتصال بنجاح!'));
  })
  .catch((err) => {
    console.error(chalk.red('✗ فشل الاتصال:'), err.message);
    process.exit(1);
  });

