const Database = require('better-sqlite3');
const path = require('path');
const chalk = require('chalk');

const dbPath = path.join(__dirname, '..', 'data', 'shadow_realms.db');

// Ensure data directory exists
const fs = require('fs');
const dataDir = path.join(__dirname, '..', 'data');
if (!fs.existsSync(dataDir)) {
  fs.mkdirSync(dataDir, { recursive: true });
}

const db = new Database(dbPath);

// Enable WAL mode for better performance
db.pragma('journal_mode = WAL');

// ==================== TABLES ====================

db.exec(`
  -- Players table
  CREATE TABLE IF NOT EXISTS players (
    user_id TEXT PRIMARY KEY,
    username TEXT NOT NULL,
    level INTEGER DEFAULT 1,
    xp INTEGER DEFAULT 0,
    health INTEGER DEFAULT 100,
    max_health INTEGER DEFAULT 100,
    attack INTEGER DEFAULT 10,
    defense INTEGER DEFAULT 5,
    energy INTEGER DEFAULT 100,
    max_energy INTEGER DEFAULT 100,
    shadow_essence INTEGER DEFAULT 0,
    gold INTEGER DEFAULT 500,
    realm TEXT DEFAULT 'البداية',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    last_daily TEXT,
    daily_streak INTEGER DEFAULT 0,
    total_played INTEGER DEFAULT 0
  );

  -- Inventory table
  CREATE TABLE IF NOT EXISTS inventory (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id TEXT NOT NULL,
    item_type TEXT NOT NULL, -- weapon, armor, potion, essence, material
    item_name TEXT NOT NULL,
    item_rarity TEXT DEFAULT 'شائع', -- شائع, نادر, أسطوري, خرافي
    quantity INTEGER DEFAULT 1,
    stats TEXT, -- JSON string of stats
    equipped INTEGER DEFAULT 0,
    FOREIGN KEY (user_id) REFERENCES players(user_id)
  );

  -- Shadow creatures collected
  CREATE TABLE IF NOT EXISTS shadows (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id TEXT NOT NULL,
    shadow_name TEXT NOT NULL,
    shadow_type TEXT NOT NULL, -- ناري, مائي, ترابي, هوائي, ظلامي, نوراني
    level INTEGER DEFAULT 1,
    xp INTEGER DEFAULT 0,
    rarity TEXT DEFAULT 'شائع', -- شائع, نادر, أسطوري, خرافي
    hp INTEGER DEFAULT 50,
    attack INTEGER DEFAULT 8,
    defense INTEGER DEFAULT 4,
    speed INTEGER DEFAULT 5,
    FOREIGN KEY (user_id) REFERENCES players(user_id)
  );

  -- Guilds table
  CREATE TABLE IF NOT EXISTS guilds (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT UNIQUE NOT NULL,
    owner_id TEXT NOT NULL,
    level INTEGER DEFAULT 1,
    xp INTEGER DEFAULT 0,
    description TEXT DEFAULT 'قبيلة من نسّاجي الظل',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (owner_id) REFERENCES players(user_id)
  );

  -- Guild members
  CREATE TABLE IF NOT EXISTS guild_members (
    guild_id INTEGER NOT NULL,
    user_id TEXT NOT NULL,
    role TEXT DEFAULT 'عضو', -- زعيم, نائب, عضو, مبتدئ
    joined_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (guild_id, user_id),
    FOREIGN KEY (guild_id) REFERENCES guilds(id),
    FOREIGN KEY (user_id) REFERENCES players(user_id)
  );

  -- Server settings
  CREATE TABLE IF NOT EXISTS server_settings (
    guild_id TEXT PRIMARY KEY,
    prefix TEXT DEFAULT '!ظل',
    shadow_channel TEXT,
    welcome_enabled INTEGER DEFAULT 1,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  -- Daily rewards log
  CREATE TABLE IF NOT EXISTS daily_log (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id TEXT NOT NULL,
    date TEXT NOT NULL,
    streak INTEGER DEFAULT 0,
    amount INTEGER DEFAULT 0,
    claimed_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  -- Trade history
  CREATE TABLE IF NOT EXISTS trade_history (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    from_user TEXT NOT NULL,
    to_user TEXT NOT NULL,
    item_given TEXT,
    item_received TEXT,
    gold_amount INTEGER DEFAULT 0,
    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
  );
`);

// ==================== HELPER FUNCTIONS ====================

const playerCache = new Map();

function getPlayer(userId, username) {
  // Check cache first
  if (playerCache.has(userId)) {
    return playerCache.get(userId);
  }

  let player = db.prepare('SELECT * FROM players WHERE user_id = ?').get(userId);

  if (!player) {
    const stmt = db.prepare(`
      INSERT INTO players (user_id, username, gold, health, max_health, attack, defense, energy, max_energy)
      VALUES (?, ?, 500, 100, 100, 10, 5, 100, 100)
    `);
    stmt.run(userId, username);
    player = db.prepare('SELECT * FROM players WHERE user_id = ?').get(userId);
    console.log(chalk.green(`[NEW PLAYER] ${username} (${userId})`));
  }

  // Update username if changed
  if (player.username !== username) {
    db.prepare('UPDATE players SET username = ? WHERE user_id = ?').run(username, userId);
    player.username = username;
  }

  // Cache for 30 seconds
  playerCache.set(userId, player);
  setTimeout(() => playerCache.delete(userId), 30000);

  return player;
}

function updatePlayer(userId, data) {
  const keys = Object.keys(data);
  const values = Object.values(data);

  const setClause = keys.map(k => `${k} = ?`).join(', ');
  values.push(userId);

  db.prepare(`UPDATE players SET ${setClause} WHERE user_id = ?`).run(...values);

  // Update cache
  const cached = playerCache.get(userId);
  if (cached) {
    Object.assign(cached, data);
  }
}

function getInventory(userId) {
  return db.prepare('SELECT * FROM inventory WHERE user_id = ? ORDER BY item_rarity DESC, item_name ASC').all(userId);
}

function addItem(userId, itemType, itemName, rarity = 'شائع', quantity = 1, stats = '{}') {
  const existing = db.prepare('SELECT * FROM inventory WHERE user_id = ? AND item_name = ? AND item_type = ?').get(userId, itemName, itemType);

  if (existing) {
    db.prepare('UPDATE inventory SET quantity = quantity + ? WHERE id = ?').run(quantity, existing.id);
    return existing.id;
  } else {
    const stmt = db.prepare(`
      INSERT INTO inventory (user_id, item_type, item_name, item_rarity, quantity, stats)
      VALUES (?, ?, ?, ?, ?, ?)
    `);
    const result = stmt.run(userId, itemType, itemName, rarity, quantity, stats);
    return result.lastInsertRowid;
  }
}

function removeItem(inventoryId, quantity = 1) {
  const item = db.prepare('SELECT * FROM inventory WHERE id = ?').get(inventoryId);
  if (!item) return false;

  if (item.quantity <= quantity) {
    db.prepare('DELETE FROM inventory WHERE id = ?').run(inventoryId);
  } else {
    db.prepare('UPDATE inventory SET quantity = quantity - ? WHERE id = ?').run(quantity, inventoryId);
  }
  return true;
}

function getShadows(userId) {
  return db.prepare('SELECT * FROM shadows WHERE user_id = ? ORDER BY level DESC, rarity DESC').all(userId);
}

function addShadow(userId, shadowName, shadowType, rarity = 'شائع') {
  const stats = {
    'شائع': { hp: 40, attack: 6, defense: 3, speed: 4 },
    'نادر': { hp: 70, attack: 12, defense: 7, speed: 8 },
    'أسطوري': { hp: 120, attack: 20, defense: 12, speed: 14 },
    'خرافي': { hp: 200, attack: 35, defense: 25, speed: 22 }
  };

  const s = stats[rarity] || stats['شائع'];

  const stmt = db.prepare(`
    INSERT INTO shadows (user_id, shadow_name, shadow_type, rarity, hp, attack, defense, speed)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `);
  return stmt.run(userId, shadowName, shadowType, rarity, s.hp, s.attack, s.defense, s.speed).lastInsertRowid;
}

function getGuild(guildId) {
  return db.prepare('SELECT * FROM guilds WHERE id = ?').get(guildId);
}

function getGuildByName(name) {
  return db.prepare('SELECT * FROM guilds WHERE name = ?').get(name);
}

function getPlayerGuild(userId) {
  const member = db.prepare('SELECT guild_id FROM guild_members WHERE user_id = ?').get(userId);
  if (!member) return null;
  return db.prepare('SELECT * FROM guilds WHERE id = ?').get(member.guild_id);
}

function getServerSettings(guildId) {
  let settings = db.prepare('SELECT * FROM server_settings WHERE guild_id = ?').get(guildId);
  if (!settings) {
    db.prepare('INSERT INTO server_settings (guild_id) VALUES (?)').run(guildId);
    settings = db.prepare('SELECT * FROM server_settings WHERE guild_id = ?').get(guildId);
  }
  return settings;
}

function getLeaderboard(type = 'level', limit = 10) {
  let query;
  switch (type) {
    case 'gold':
      query = 'SELECT user_id, username, gold FROM players ORDER BY gold DESC LIMIT ?';
      break;
    case 'shadow_essence':
      query = 'SELECT user_id, username, shadow_essence FROM players ORDER BY shadow_essence DESC LIMIT ?';
      break;
    case 'level':
    default:
      query = 'SELECT user_id, username, level, xp FROM players ORDER BY level DESC, xp DESC LIMIT ?';
      break;
  }
  return db.prepare(query).all(limit);
}

function getTopGuilds(limit = 10) {
  return db.prepare('SELECT g.*, COUNT(gm.user_id) as member_count FROM guilds g LEFT JOIN guild_members gm ON g.id = gm.guild_id GROUP BY g.id ORDER BY g.level DESC, g.xp DESC LIMIT ?').all(limit);
}

module.exports = {
  db,
  getPlayer,
  updatePlayer,
  getInventory,
  addItem,
  removeItem,
  getShadows,
  addShadow,
  getGuild,
  getGuildByName,
  getPlayerGuild,
  getServerSettings,
  getLeaderboard,
  getTopGuilds,
  playerCache
};

