const path = require('path');
const chalk = require('chalk');
const fs = require('fs');

const dataDir = path.join(__dirname, '..', 'data');
if (!fs.existsSync(dataDir)) {
  fs.mkdirSync(dataDir, { recursive: true });
}

const dbPath = path.join(dataDir, 'shadow_realms.db');
let db = null;

// Initialize database with sql.js
async function initDatabase() {
  const initSqlJs = require('sql.js');
  const SQL = await initSqlJs();

  // Load existing database or create new one
  if (fs.existsSync(dbPath)) {
    const buffer = fs.readFileSync(dbPath);
    db = new SQL.Database(buffer);
  } else {
    db = new SQL.Database();
  }

  createTables();
  saveDatabase();

  console.log(chalk.green(`✓ تم تحميل قاعدة البيانات (${fs.existsSync(dbPath) ? 'موجودة' : 'جديدة'})`));
  return db;
}

function saveDatabase() {
  if (!db) return;
  const data = db.export();
  const buffer = Buffer.from(data);
  fs.writeFileSync(dbPath, buffer);
}

function createTables() {
  db.run(`
    CREATE TABLE IF NOT EXISTS players (
      user_id TEXT PRIMARY KEY,
      username TEXT NOT NULL,
      level INTEGER DEFAULT 1,
      xp INTEGER DEFAULT 0,
      health INTEGER DEFAULT 100,
      max_health INTEGER DEFAULT 100,
      attack INTEGER DEFAULT 10,
      defense INTEGER DEFAULT 5,
      energy INTEGER DEFAULT 100,
      max_energy INTEGER DEFAULT 100,
      shadow_essence INTEGER DEFAULT 0,
      gold INTEGER DEFAULT 500,
      realm TEXT DEFAULT 'البداية',
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      last_daily TEXT,
      daily_streak INTEGER DEFAULT 0,
      total_played INTEGER DEFAULT 0
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS inventory (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id TEXT NOT NULL,
      item_type TEXT NOT NULL,
      item_name TEXT NOT NULL,
      item_rarity TEXT DEFAULT 'شائع',
      quantity INTEGER DEFAULT 1,
      stats TEXT DEFAULT '{}',
      equipped INTEGER DEFAULT 0
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS shadows (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id TEXT NOT NULL,
      shadow_name TEXT NOT NULL,
      shadow_type TEXT NOT NULL,
      level INTEGER DEFAULT 1,
      xp INTEGER DEFAULT 0,
      rarity TEXT DEFAULT 'شائع',
      hp INTEGER DEFAULT 50,
      attack INTEGER DEFAULT 8,
      defense INTEGER DEFAULT 4,
      speed INTEGER DEFAULT 5
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS guilds (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT UNIQUE NOT NULL,
      owner_id TEXT NOT NULL,
      level INTEGER DEFAULT 1,
      xp INTEGER DEFAULT 0,
      description TEXT DEFAULT 'قبيلة من نسّاجي الظل',
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS guild_members (
      guild_id INTEGER NOT NULL,
      user_id TEXT NOT NULL,
      role TEXT DEFAULT 'عضو',
      joined_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      PRIMARY KEY (guild_id, user_id)
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS server_settings (
      guild_id TEXT PRIMARY KEY,
      prefix TEXT DEFAULT '!ظل',
      shadow_channel TEXT,
      welcome_enabled INTEGER DEFAULT 1,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS daily_log (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id TEXT NOT NULL,
      date TEXT NOT NULL,
      streak INTEGER DEFAULT 0,
      amount INTEGER DEFAULT 0,
      claimed_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS trade_history (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      from_user TEXT NOT NULL,
      to_user TEXT NOT NULL,
      item_given TEXT,
      item_received TEXT,
      gold_amount INTEGER DEFAULT 0,
      timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `);
}

// Query helpers
function getQuery(sql, params = []) {
  const stmt = db.prepare(sql);
  if (params.length > 0) stmt.bind(params);
  if (stmt.step()) {
    const result = stmt.getAsObject();
    stmt.free();
    return result;
  }
  stmt.free();
  return undefined;
}

function allQuery(sql, params = []) {
  const stmt = db.prepare(sql);
  if (params.length > 0) stmt.bind(params);
  const results = [];
  while (stmt.step()) {
    results.push(stmt.getAsObject());
  }
  stmt.free();
  return results;
}

function runQuery(sql, params = []) {
  db.run(sql, params);
  saveDatabase();
  return { lastInsertRowid: db.exec("SELECT last_insert_rowid() as id")[0]?.values[0][0] };
}

// ==================== HELPER FUNCTIONS ====================

const playerCache = new Map();

function getPlayer(userId, username) {
  if (playerCache.has(userId)) {
    return playerCache.get(userId);
  }

  let player = getQuery('SELECT * FROM players WHERE user_id = ?', [userId]);

  if (!player) {
    runQuery(
      'INSERT INTO players (user_id, username, gold, health, max_health, attack, defense, energy, max_energy) VALUES (?, ?, 500, 100, 100, 10, 5, 100, 100)',
      [userId, username]
    );
    player = getQuery('SELECT * FROM players WHERE user_id = ?', [userId]);
    console.log(chalk.green(`[NEW PLAYER] ${username} (${userId})`));
  }

  if (player && player.username !== username) {
    runQuery('UPDATE players SET username = ? WHERE user_id = ?', [username, userId]);
    player.username = username;
  }

  playerCache.set(userId, player);
  setTimeout(() => playerCache.delete(userId), 30000);

  return player;
}

function updatePlayer(userId, data) {
  const keys = Object.keys(data);
  const values = Object.values(data);

  const setClause = keys.map(k => `${k} = ?`).join(', ');
  values.push(userId);

  runQuery(`UPDATE players SET ${setClause} WHERE user_id = ?`, values);

  const cached = playerCache.get(userId);
  if (cached) {
    Object.assign(cached, data);
  }
}

function getInventory(userId) {
  return allQuery('SELECT * FROM inventory WHERE user_id = ? ORDER BY item_rarity DESC, item_name ASC', [userId]);
}

function addItem(userId, itemType, itemName, rarity = 'شائع', quantity = 1, stats = '{}') {
  const existing = getQuery('SELECT * FROM inventory WHERE user_id = ? AND item_name = ? AND item_type = ?', [userId, itemName, itemType]);

  if (existing) {
    runQuery('UPDATE inventory SET quantity = quantity + ? WHERE id = ?', [quantity, existing.id]);
    return existing.id;
  } else {
    const result = runQuery(
      'INSERT INTO inventory (user_id, item_type, item_name, item_rarity, quantity, stats) VALUES (?, ?, ?, ?, ?, ?)',
      [userId, itemType, itemName, rarity, quantity, stats]
    );
    return result.lastInsertRowid;
  }
}

function removeItem(inventoryId, quantity = 1) {
  const item = getQuery('SELECT * FROM inventory WHERE id = ?', [inventoryId]);
  if (!item) return false;

  if (item.quantity <= quantity) {
    runQuery('DELETE FROM inventory WHERE id = ?', [inventoryId]);
  } else {
    runQuery('UPDATE inventory SET quantity = quantity - ? WHERE id = ?', [quantity, inventoryId]);
  }
  return true;
}

function getShadows(userId) {
  return allQuery('SELECT * FROM shadows WHERE user_id = ? ORDER BY level DESC, rarity DESC', [userId]);
}

function addShadow(userId, shadowName, shadowType, rarity = 'شائع') {
  const stats = {
    'شائع': { hp: 40, attack: 6, defense: 3, speed: 4 },
    'نادر': { hp: 70, attack: 12, defense: 7, speed: 8 },
    'أسطوري': { hp: 120, attack: 20, defense: 12, speed: 14 },
    'خرافي': { hp: 200, attack: 35, defense: 25, speed: 22 }
  };

  const s = stats[rarity] || stats['شائع'];

  const result = runQuery(
    'INSERT INTO shadows (user_id, shadow_name, shadow_type, rarity, hp, attack, defense, speed) VALUES (?, ?, ?, ?, ?, ?, ?, ?)',
    [userId, shadowName, shadowType, rarity, s.hp, s.attack, s.defense, s.speed]
  );
  return result.lastInsertRowid;
}

function getGuild(guildId) {
  return getQuery('SELECT * FROM guilds WHERE id = ?', [guildId]);
}

function getGuildByName(name) {
  return getQuery('SELECT * FROM guilds WHERE name = ?', [name]);
}

function getPlayerGuild(userId) {
  const member = getQuery('SELECT guild_id FROM guild_members WHERE user_id = ?', [userId]);
  if (!member) return null;
  return getQuery('SELECT * FROM guilds WHERE id = ?', [member.guild_id]);
}

function getGuildMembers(guildId) {
  return allQuery(
    'SELECT gm.*, p.username FROM guild_members gm JOIN players p ON gm.user_id = p.user_id WHERE gm.guild_id = ? ORDER BY gm.role DESC, gm.joined_at ASC',
    [guildId]
  );
}

function getServerSettings(guildId) {
  let settings = getQuery('SELECT * FROM server_settings WHERE guild_id = ?', [guildId]);
  if (!settings) {
    runQuery('INSERT INTO server_settings (guild_id) VALUES (?)', [guildId]);
    settings = getQuery('SELECT * FROM server_settings WHERE guild_id = ?', [guildId]);
  }
  return settings;
}

function getLeaderboard(type = 'level', limit = 10) {
  let query;
  switch (type) {
    case 'gold':
      query = 'SELECT user_id, username, gold FROM players ORDER BY gold DESC LIMIT ?';
      break;
    case 'shadow_essence':
      query = 'SELECT user_id, username, shadow_essence FROM players ORDER BY shadow_essence DESC LIMIT ?';
      break;
    case 'level':
    default:
      query = 'SELECT user_id, username, level, xp FROM players ORDER BY level DESC, xp DESC LIMIT ?';
      break;
  }
  return allQuery(query, [limit]);
}

function getTopGuilds(limit = 10) {
  return allQuery(
    'SELECT g.*, COUNT(gm.user_id) as member_count FROM guilds g LEFT JOIN guild_members gm ON g.id = gm.guild_id GROUP BY g.id ORDER BY g.level DESC, g.xp DESC LIMIT ?',
    [limit]
  );
}

module.exports = {
  db: null,
  initDatabase,
  getPlayer,
  updatePlayer,
  getInventory,
  addItem,
  removeItem,
  getShadows,
  addShadow,
  getGuild,
  getGuildByName,
  getPlayerGuild,
  getGuildMembers,
  getServerSettings,
  getLeaderboard,
  getTopGuilds,
  playerCache,
  runQuery,
  allQuery,
  getQuery,
  saveDatabase
};

// ==========================================
//  🌑 ممالك الظل • SHADOW REALMS
//  بوت لعبة ديسكورد RPG غامر
//  من تصميم pi-coding-agent
// ==========================================

const { Client, GatewayIntentBits, Collection } = require('discord.js');
const fs = require('fs');
const path = require('path');
const chalk = require('chalk');
const config = require('./config.json');

// Validate config
if (config.token === 'YOUR_BOT_TOKEN_HERE') {
  console.error(chalk.red('✗ يرجى وضع التوكن الخاص بالبوت في ملف config.json'));
  console.error(chalk.yellow('  اذهب إلى https://discord.com/developers/applications وأنشئ تطبيقاً'));
  process.exit(1);
}

async function main() {
  // Initialize database first
  console.log(chalk.cyan('📂 جاري تهيئة قاعدة البيانات...'));
  const dbModule = require('./database/db');
  await dbModule.initDatabase();
  // Share db reference
  const dbRef = dbModule;

  // Create client
  const client = new Client({
    intents: [
      GatewayIntentBits.Guilds,
      GatewayIntentBits.GuildMessages,
      GatewayIntentBits.MessageContent,
      GatewayIntentBits.GuildMembers
    ]
  });

  // Commands collection
  client.commands = new Collection();
  client.config = config;

  // Load commands
  const commandFolders = ['economy', 'exploration', 'battle', 'collection', 'crafting', 'guild', 'info'];

  console.log(chalk.cyan('\n📂 جاري تحميل الأوامر...\n'));

  for (const folder of commandFolders) {
    const commandsPath = path.join(__dirname, 'commands', folder);
    if (!fs.existsSync(commandsPath)) continue;

    const commandFiles = fs.readdirSync(commandsPath).filter(file => file.endsWith('.js'));

    for (const file of commandFiles) {
      const filePath = path.join(commandsPath, file);
      const command = require(filePath);

      if ('data' in command && 'execute' in command) {
        client.commands.set(command.data.name, command);
        console.log(chalk.green(`  ✓ ${command.data.name}`));
      } else {
        console.log(chalk.yellow(`  ⚠ ${file} مفقود execute أو data`));
      }
    }
  }

  // Load events
  console.log(chalk.cyan('\n📂 جاري تحميل الأحداث...\n'));

  const eventsPath = path.join(__dirname, 'events');
  const eventFiles = fs.readdirSync(eventsPath).filter(file => file.endsWith('.js'));

  for (const file of eventFiles) {
    const filePath = path.join(eventsPath, file);
    const event = require(filePath);

    if (event.once) {
      client.once(event.name, (...args) => event.execute(...args));
    } else {
      client.on(event.name, (...args) => event.execute(...args));
    }

    console.log(chalk.green(`  ✓ ${event.name}`));
  }

  // Handle prefix commands (optional)
  client.on('messageCreate', async (message) => {
    if (message.author.bot) return;
    if (!message.content.startsWith(config.prefix)) return;

    const args = message.content.slice(config.prefix.length).trim().split(/ +/);
    const commandName = args.shift()?.toLowerCase();

    if (!commandName) return;

    const prefixCommands = {
      'profile': async (msg) => {
        const { getPlayer, getShadows, getInventory } = require('./database/db');
        const { createPlayerProfile } = require('./utils/embeds');
        const player = getPlayer(msg.author.id, msg.author.username);
        const shadows = getShadows(msg.author.id);
        const inventory = getInventory(msg.author.id);
        const embed = createPlayerProfile(player, shadows, inventory);
        await msg.reply({ embeds: [embed] });
      },
      'daily': async (msg) => {
        await msg.reply('📌 استخدم `/daily` للحصول على مكافأتك اليومية!');
      },
      'help': async (msg) => {
        const embed = require('./utils/embeds').createBaseEmbed('🌑 ممالك الظل • دليل الأوامر',
          'استخدم الأوامر بالـ `/` للتفاعل مع البوت:\n\n' +
          '👤 `/profile` - ملفك الشخصي\n' +
          '💰 `/daily` - المكافأة اليومية\n' +
          '💰 `/balance` - رصيدك\n' +
          '🏪 `/shop` - المتجر\n' +
          '🌍 `/explore` - استكشاف\n' +
          '⚔️ `/hunt` - صيد\n' +
          '🤺 `/duel` - مبارزة\n' +
          '🏰 `/guild` - القبائل\n' +
          '🎒 `/inventory` - المخزون\n' +
          '📊 `/leaderboard` - لوحة الشرف',
          config.colors.primary
        );
        await msg.reply({ embeds: [embed] });
      }
    };

    const cmd = prefixCommands[commandName];
    if (cmd) {
      try {
        await cmd(message);
      } catch (error) {
        console.error(chalk.red(`[PREFIX ERROR] ${error.message}`));
        await message.reply('❌ حدث خطأ.');
      }
    }
  });

  // Handle unhandled errors
  process.on('unhandledRejection', (error) => {
    console.error(chalk.red('❌ خطأ غير متوقع:'), error.message);
  });

  process.on('uncaughtException', (error) => {
    console.error(chalk.red('❌ استثناء غير متوقع:'), error.message);
  });

  // Login
  console.log(chalk.magenta('\n🌑 جاري تشغيل ممالك الظل...\n'));

  client.login(config.token)
    .then(() => {
      console.log(chalk.green('✓ تم الاتصال بنجاح!'));
    })
    .catch((err) => {
      console.error(chalk.red('✗ فشل الاتصال:'), err.message);
      process.exit(1);
    });
}

main().catch(err => {
  console.error(chalk.red('✗ فشل بدء التشغيل:'), err.message);
  process.exit(1);
});

