const path = require('path');
const chalk = require('chalk');
const fs = require('fs');

const dataDir = path.join(__dirname, '..', 'data');
if (!fs.existsSync(dataDir)) {
  fs.mkdirSync(dataDir, { recursive: true });
}

const dbPath = path.join(dataDir, 'shadow_realms.db');
let db = null;

async function initDatabase() {
  const initSqlJs = require('sql.js');
  const SQL = await initSqlJs();

  if (fs.existsSync(dbPath)) {
    const buffer = fs.readFileSync(dbPath);
    db = new SQL.Database(buffer);
  } else {
    db = new SQL.Database();
  }

  createTables();
  saveDatabase();

  console.log(chalk.green(`✓ تم تحميل قاعدة البيانات (${fs.existsSync(dbPath) ? 'موجودة' : 'جديدة'})`));
  return db;
}

function saveDatabase() {
  if (!db) return;
  const data = db.export();
  const buffer = Buffer.from(data);
  fs.writeFileSync(dbPath, buffer);
}

function createTables() {
  // ====== CORE TABLES ======
  db.run(`CREATE TABLE IF NOT EXISTS players (
    user_id TEXT PRIMARY KEY, username TEXT NOT NULL,
    level INTEGER DEFAULT 1, xp INTEGER DEFAULT 0,
    health INTEGER DEFAULT 100, max_health INTEGER DEFAULT 100,
    attack INTEGER DEFAULT 10, defense INTEGER DEFAULT 5,
    energy INTEGER DEFAULT 100, max_energy INTEGER DEFAULT 100,
    shadow_essence INTEGER DEFAULT 0, gold INTEGER DEFAULT 500,
    realm TEXT DEFAULT 'البداية', created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    last_daily TEXT, daily_streak INTEGER DEFAULT 0, total_played INTEGER DEFAULT 0,
    prestige INTEGER DEFAULT 0, luck INTEGER DEFAULT 5,
    crit_chance REAL DEFAULT 5.0, crit_damage REAL DEFAULT 150.0,
    dodge_chance REAL DEFAULT 5.0
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS inventory (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id TEXT NOT NULL, item_type TEXT NOT NULL,
    item_name TEXT NOT NULL, item_rarity TEXT DEFAULT 'شائع',
    quantity INTEGER DEFAULT 1, stats TEXT DEFAULT '{}', equipped INTEGER DEFAULT 0
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS shadows (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id TEXT NOT NULL, shadow_name TEXT NOT NULL,
    shadow_type TEXT NOT NULL, level INTEGER DEFAULT 1, xp INTEGER DEFAULT 0,
    rarity TEXT DEFAULT 'شائع', hp INTEGER DEFAULT 50,
    attack INTEGER DEFAULT 8, defense INTEGER DEFAULT 4, speed INTEGER DEFAULT 5,
    wins INTEGER DEFAULT 0, losses INTEGER DEFAULT 0
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS guilds (
    id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT UNIQUE NOT NULL,
    owner_id TEXT NOT NULL, level INTEGER DEFAULT 1, xp INTEGER DEFAULT 0,
    description TEXT DEFAULT 'قبيلة من نسّاجي الظل', created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    wins INTEGER DEFAULT 0, losses INTEGER DEFAULT 0, treasury INTEGER DEFAULT 0
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS guild_members (
    guild_id INTEGER NOT NULL, user_id TEXT NOT NULL,
    role TEXT DEFAULT 'عضو', joined_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    contribution INTEGER DEFAULT 0, PRIMARY KEY (guild_id, user_id)
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS server_settings (
    guild_id TEXT PRIMARY KEY, prefix TEXT DEFAULT '!ظل',
    shadow_channel TEXT, welcome_enabled INTEGER DEFAULT 1,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS daily_log (
    id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
    date TEXT NOT NULL, streak INTEGER DEFAULT 0, amount INTEGER DEFAULT 0,
    claimed_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS trade_history (
    id INTEGER PRIMARY KEY AUTOINCREMENT, from_user TEXT NOT NULL,
    to_user TEXT NOT NULL, item_given TEXT, item_received TEXT,
    gold_amount INTEGER DEFAULT 0, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  // ====== NEW ADVANCED TABLES ======

  db.run(`CREATE TABLE IF NOT EXISTS achievements (
    id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
    achievement_key TEXT NOT NULL, unlocked_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(user_id, achievement_key)
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS quests (
    id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
    quest_key TEXT NOT NULL, progress INTEGER DEFAULT 0,
    target INTEGER DEFAULT 1, completed INTEGER DEFAULT 0,
    reward_claimed INTEGER DEFAULT 0, completed_at DATETIME,
    UNIQUE(user_id, quest_key)
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS market_listings (
    id INTEGER PRIMARY KEY AUTOINCREMENT, seller_id TEXT NOT NULL,
    item_name TEXT NOT NULL, item_type TEXT NOT NULL,
    item_rarity TEXT DEFAULT 'شائع', quantity INTEGER DEFAULT 1,
    stats TEXT DEFAULT '{}', price INTEGER NOT NULL,
    listed_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS friends (
    user_id TEXT NOT NULL, friend_id TEXT NOT NULL,
    status TEXT DEFAULT 'pending', created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (user_id, friend_id)
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS player_skills (
    user_id TEXT PRIMARY KEY, specialization TEXT DEFAULT 'مقاتل',
    skill_points INTEGER DEFAULT 0, mining_level INTEGER DEFAULT 1,
    mining_xp INTEGER DEFAULT 0, fishing_level INTEGER DEFAULT 1,
    fishing_xp INTEGER DEFAULT 0
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS dungeon_progress (
    user_id TEXT PRIMARY KEY, current_floor INTEGER DEFAULT 1,
    max_floor INTEGER DEFAULT 1, health INTEGER DEFAULT 100,
    max_hp INTEGER DEFAULT 100, attempts INTEGER DEFAULT 0,
    last_run DATETIME
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS world_boss (
    id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL,
    hp INTEGER NOT NULL, max_hp INTEGER NOT NULL,
    level INTEGER DEFAULT 1, attack INTEGER DEFAULT 50,
    defense INTEGER DEFAULT 30, reward_pool INTEGER DEFAULT 0,
    spawn_time DATETIME, defeated INTEGER DEFAULT 0, active INTEGER DEFAULT 0
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS world_boss_damage (
    boss_id INTEGER NOT NULL, user_id TEXT NOT NULL,
    damage INTEGER DEFAULT 0, PRIMARY KEY (boss_id, user_id)
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS lottery_tickets (
    id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
    ticket_number INTEGER NOT NULL, bought_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS shadow_fusions (
    id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
    result_shadow_id INTEGER NOT NULL, fusion_date DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS marriages (
    id INTEGER PRIMARY KEY AUTOINCREMENT, user1_id TEXT NOT NULL,
    user2_id TEXT NOT NULL, married_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(user1_id, user2_id)
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS boosters (
    id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
    booster_type TEXT NOT NULL, multiplier REAL DEFAULT 1.5,
    duration_minutes INTEGER DEFAULT 30, activated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    expires_at DATETIME NOT NULL
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS server_events (
    id INTEGER PRIMARY KEY AUTOINCREMENT, event_type TEXT NOT NULL,
    active INTEGER DEFAULT 0, started_by TEXT,
    started_at DATETIME DEFAULT CURRENT_TIMESTAMP, ends_at DATETIME
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS dungeon_leaderboard (
    user_id TEXT PRIMARY KEY, best_floor INTEGER DEFAULT 1,
    total_runs INTEGER DEFAULT 0, total_kills INTEGER DEFAULT 0,
    fastest_time INTEGER DEFAULT 0
  )`);
}

// ====== QUERY HELPERS ======

function getQuery(sql, params = []) {
  if (!db) return null;
  try {
    const stmt = db.prepare(sql);
    if (params.length > 0) stmt.bind(params);
    if (stmt.step()) {
      const result = stmt.getAsObject();
      stmt.free();
      return result;
    }
    stmt.free();
  } catch (e) { console.error('getQuery error:', e.message, sql); }
  return undefined;
}

function allQuery(sql, params = []) {
  if (!db) return [];
  try {
    const stmt = db.prepare(sql);
    if (params.length > 0) stmt.bind(params);
    const results = [];
    while (stmt.step()) {
      results.push(stmt.getAsObject());
    }
    stmt.free();
    return results;
  } catch (e) { console.error('allQuery error:', e.message, sql); }
  return [];
}

function runQuery(sql, params = []) {
  if (!db) return null;
  try {
    db.run(sql, params);
    saveDatabase();
    const result = db.exec("SELECT last_insert_rowid() as id");
    const lastId = result && result[0] && result[0].values ? result[0].values[0][0] : null;
    return { lastInsertRowid: lastId, changes: db.getRowsModified() };
  } catch (e) { console.error('runQuery error:', e.message, sql); }
  return null;
}

// ====== PLAYER FUNCTIONS ======

const playerCache = new Map();

function getPlayer(userId, username) {
  if (playerCache.has(userId)) return playerCache.get(userId);

  let player = getQuery('SELECT * FROM players WHERE user_id = ?', [userId]);

  if (!player) {
    runQuery('INSERT INTO players (user_id, username) VALUES (?, ?)', [userId, username]);
    player = getQuery('SELECT * FROM players WHERE user_id = ?', [userId]);
    console.log(chalk.green(`[NEW PLAYER] ${username} (${userId})`));

    // Initialize skills
    runQuery('INSERT OR IGNORE INTO player_skills (user_id) VALUES (?)', [userId]);
  }

  if (player && player.username !== username) {
    runQuery('UPDATE players SET username = ? WHERE user_id = ?', [username, userId]);
    player.username = username;
  }

  playerCache.set(userId, player);
  setTimeout(() => playerCache.delete(userId), 30000);

  return player;
}

function updatePlayer(userId, data) {
  const keys = Object.keys(data);
  const values = Object.values(data);
  if (keys.length === 0) return;
  const setClause = keys.map(k => `${k} = ?`).join(', ');
  values.push(userId);
  runQuery(`UPDATE players SET ${setClause} WHERE user_id = ?`, values);
  const cached = playerCache.get(userId);
  if (cached) Object.assign(cached, data);
}

function getInventory(userId) {
  return allQuery('SELECT * FROM inventory WHERE user_id = ? ORDER BY item_rarity DESC, item_name ASC', [userId]);
}

function addItem(userId, itemType, itemName, rarity = 'شائع', quantity = 1, stats = '{}') {
  const existing = getQuery('SELECT * FROM inventory WHERE user_id = ? AND item_name = ? AND item_type = ?', [userId, itemName, itemType]);
  if (existing) {
    runQuery('UPDATE inventory SET quantity = quantity + ? WHERE id = ?', [quantity, existing.id]);
    return existing.id;
  } else {
    const result = runQuery('INSERT INTO inventory (user_id, item_type, item_name, item_rarity, quantity, stats) VALUES (?, ?, ?, ?, ?, ?)', [userId, itemType, itemName, rarity, quantity, stats]);
    return result ? result.lastInsertRowid : null;
  }
}

function removeItem(inventoryId, quantity = 1) {
  const item = getQuery('SELECT * FROM inventory WHERE id = ?', [inventoryId]);
  if (!item) return false;
  if (item.quantity <= quantity) {
    runQuery('DELETE FROM inventory WHERE id = ?', [inventoryId]);
  } else {
    runQuery('UPDATE inventory SET quantity = quantity - ? WHERE id = ?', [quantity, inventoryId]);
  }
  return true;
}

function getShadows(userId) {
  return allQuery('SELECT * FROM shadows WHERE user_id = ? ORDER BY level DESC, rarity DESC', [userId]);
}

function addShadow(userId, shadowName, shadowType, rarity = 'شائع', level = 1) {
  const stats = {
    'شائع': { hp: 40, attack: 6, defense: 3, speed: 4 },
    'نادر': { hp: 70, attack: 12, defense: 7, speed: 8 },
    'أسطوري': { hp: 120, attack: 20, defense: 12, speed: 14 },
    'خرافي': { hp: 200, attack: 35, defense: 25, speed: 22 }
  };
  const s = stats[rarity] || stats['شائع'];
  const hp = s.hp + (level - 1) * 5;
  const atk = s.attack + (level - 1) * 2;
  const def = s.defense + (level - 1) * 1;
  const spd = s.speed + (level - 1) * 1;

  const result = runQuery(
    'INSERT INTO shadows (user_id, shadow_name, shadow_type, rarity, level, hp, attack, defense, speed) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)',
    [userId, shadowName, shadowType, rarity, level, hp, atk, def, spd]
  );
  return result ? result.lastInsertRowid : null;
}

// ====== GUILD FUNCTIONS ======

function getGuild(guildId) {
  return getQuery('SELECT * FROM guilds WHERE id = ?', [guildId]);
}

function getGuildByName(name) {
  return getQuery('SELECT * FROM guilds WHERE name = ?', [name]);
}

function getPlayerGuild(userId) {
  const member = getQuery('SELECT guild_id FROM guild_members WHERE user_id = ?', [userId]);
  if (!member) return null;
  return getQuery('SELECT * FROM guilds WHERE id = ?', [member.guild_id]);
}

function getGuildMembers(guildId) {
  return allQuery(
    'SELECT gm.*, p.username FROM guild_members gm JOIN players p ON gm.user_id = p.user_id WHERE gm.guild_id = ? ORDER BY gm.role DESC, gm.joined_at ASC',
    [guildId]
  );
}

// ====== ACHIEVEMENT FUNCTIONS ======

function getAchievements(userId) {
  return allQuery('SELECT * FROM achievements WHERE user_id = ?', [userId]);
}

function unlockAchievement(userId, key) {
  const existing = getQuery('SELECT * FROM achievements WHERE user_id = ? AND achievement_key = ?', [userId, key]);
  if (existing) return false;
  runQuery('INSERT INTO achievements (user_id, achievement_key) VALUES (?, ?)', [userId, key]);
  return true;
}

function checkAchievements(userId) {
  const player = getPlayer(userId, '');
  const shadows = getShadows(userId);
  const inv = getInventory(userId);
  const skills = getQuery('SELECT * FROM player_skills WHERE user_id = ?', [userId]);
  const guild = getPlayerGuild(userId);
  const unlocked = new Set(getAchievements(userId).map(a => a.achievement_key));
  const newAchievements = [];

  const checks = [
    { key: 'first_join', condition: true, name: '👋 الخطوة الأولى', desc: 'انضم إلى عالم الظل' },
    { key: 'level_5', condition: player.level >= 5, name: '⭐ مبتدئ الظل', desc: 'صول إلى المستوى 5' },
    { key: 'level_10', condition: player.level >= 10, name: '🌟 محارب الظل', desc: 'صول إلى المستوى 10' },
    { key: 'level_25', condition: player.level >= 25, name: '💫 فارس الظل', desc: 'صول إلى المستوى 25' },
    { key: 'level_50', condition: player.level >= 50, name: '👑 سيد الظل', desc: 'صول إلى المستوى 50' },
    { key: 'level_100', condition: player.level >= 100, name: '🌀 أسطورة الظل', desc: 'صول إلى المستوى 100' },
    { key: 'gold_1000', condition: player.gold >= 1000, name: '💰 تاجر مبتدئ', desc: 'جمع 1,000 ذهب' },
    { key: 'gold_10000', condition: player.gold >= 10000, name: '💰 تاجر محترف', desc: 'جمع 10,000 ذهب' },
    { key: 'gold_100000', condition: player.gold >= 100000, name: '💰 ملياردير الظل', desc: 'جمع 100,000 ذهب' },
    { key: 'shadow_10', condition: (player.shadow_essence || 0) >= 10, name: '💎 جامع الجواهر', desc: 'جمع 10 جوهر ظل' },
    { key: 'shadow_100', condition: (player.shadow_essence || 0) >= 100, name: '💎 تاجر الجواهر', desc: 'جمع 100 جوهر ظل' },
    { key: 'shadows_5', condition: shadows.length >= 5, name: '👾 صياد الظلال', desc: 'جمع 5 مخلوقات ظل' },
    { key: 'shadows_15', condition: shadows.length >= 15, name: '👾 مربي الظلال', desc: 'جمع 15 مخلوق ظل' },
    { key: 'shadows_30', condition: shadows.length >= 30, name: '👾 جامع الظلال', desc: 'جمع 30 مخلوق ظل' },
    { key: 'rarity_nader', condition: shadows.some(s => s.rarity === 'نادر'), name: '🟦 صائد النوادر', desc: 'احصل على مخلوق نادر' },
    { key: 'rarity_os-tory', condition: shadows.some(s => s.rarity === 'أسطوري'), name: '🟨 صائد الأساطير', desc: 'احصل على مخلوق أسطوري' },
    { key: 'rarity_khorafi', condition: shadows.some(s => s.rarity === 'خرافي'), name: '🟪 صائد الخرافات', desc: 'احصل على مخلوق خرافي' },
    { key: 'daily_7', condition: (player.daily_streak || 0) >= 7, name: '🔥 أسبوعي', desc: 'حافظ على السلسلة اليومية 7 أيام' },
    { key: 'daily_30', condition: (player.daily_streak || 0) >= 30, name: '🔥 شهري', desc: 'حافظ على السلسلة اليومية 30 يومًا' },
    { key: 'guild_create', condition: guild !== null, name: '🏰 مؤسس', desc: 'انضم إلى قبيلة' },
    { key: 'prestige_1', condition: (player.prestige || 0) >= 1, name: '🌀 مت prestigue', desc: 'اول مرة' },
    { key: 'dungeon_10', condition: true, name: '🚪 مستكشف الزنازين', desc: 'ادخل الزنزانة لأول مرة' }, // Check dungeon
    { key: 'inv_50', condition: inv.length >= 50, name: '📦 جامع', desc: 'امتلك 50 عنصرًا في المخزون' },
    { key: 'streak_5', condition: (player.daily_streak || 0) >= 5, name: '🔥 ملتزم', desc: 'حافظ على سلسلة 5 أيام' },
    { key: 'first_fusion', condition: false, name: '🔮 دامج الظلال', desc: 'قم بدمج مخلوقين ظل' }, // Check via fusion table
  ];

  // Check fusion
  const fusions = allQuery('SELECT * FROM shadow_fusions WHERE user_id = ?', [userId]);
  const fusionCheck = checks.find(c => c.key === 'first_fusion');
  if (fusionCheck) fusionCheck.condition = fusions.length > 0;

  // Check dungeon
  const dungeon = getQuery('SELECT * FROM dungeon_progress WHERE user_id = ?', [userId]);
  const dungeonCheck = checks.find(c => c.key === 'dungeon_10');
  if (dungeonCheck) dungeonCheck.condition = dungeon && dungeon.max_floor >= 1;

  // Check marriage
  const marriage = getQuery('SELECT * FROM marriages WHERE user1_id = ? OR user2_id = ?', [userId, userId]);
  if (marriage) {
    checks.push({ key: 'love_found', condition: true, name: '💑 وجد الحب', desc: 'تزوج لاعبًا آخر' });
  }

  for (const check of checks) {
    if (check.condition && !unlocked.has(check.key)) {
      unlockAchievement(userId, check.key);
      newAchievements.push(check);
    }
  }

  return newAchievements;
}

// ====== QUEST FUNCTIONS ======

const dailyQuests = [
  { key: 'daily_hunt', name: '🎯 صياد اليوم', desc: 'اصطد 3 مخلوقات ظل', target: 3, reward: { gold: 200, xp: 50, essence: 10 } },
  { key: 'daily_explore', name: '🌍 مستكشف اليوم', desc: 'استكشف 5 مرات', target: 5, reward: { gold: 150, xp: 40, essence: 5 } },
  { key: 'daily_gold', name: '💰 كاسب اليوم', desc: 'اكسب 500 ذهب', target: 500, reward: { gold: 300, xp: 60, essence: 15 } },
  { key: 'daily_kill', name: '⚔️ قاتل اليوم', desc: 'اقتل 10 أعداء', target: 10, reward: { gold: 250, xp: 80, essence: 12 } },
  { key: 'daily_trade', name: '🤝 تاجر اليوم', desc: 'تداول مع لاعب', target: 1, reward: { gold: 400, xp: 100, essence: 20 } },
];

function getDailyQuestKey() {
  const today = new Date().toISOString().split('T')[0];
  // Use date to deterministically pick 3 quests
  const dayNum = today.split('-').reduce((a, b) => a + parseInt(b), 0);
  const shuffled = [...dailyQuests].sort((a, b) => {
    const ha = (dayNum * a.key.length + a.key.charCodeAt(0)) % 100;
    const hb = (dayNum * b.key.length + b.key.charCodeAt(0)) % 100;
    return ha - hb;
  });
  return shuffled.slice(0, 3);
}

function initDailyQuests(userId) {
  const today = new Date().toISOString().split('T')[0];
  const quests = getDailyQuestKey();

  for (const q of quests) {
    const existing = getQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key = ?', [userId, `${q.key}_${today}`]);
    if (!existing) {
      runQuery('INSERT INTO quests (user_id, quest_key, progress, target) VALUES (?, ?, 0, ?)', [userId, `${q.key}_${today}`, q.target]);
    }
  }
}

function getQuests(userId) {
  const today = new Date().toISOString().split('T')[0];
  const quests = allQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key LIKE ?', [userId, `%_${today}`]);
  // If no quests today, initialize
  if (quests.length === 0) {
    initDailyQuests(userId);
    return allQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key LIKE ?', [userId, `%_${today}`]);
  }
  return quests;
}

function progressQuest(userId, key, amount = 1) {
  const today = new Date().toISOString().split('T')[0];
  const quest = getQuery('SELECT * FROM quests WHERE user_id = ? AND quest_key = ?', [userId, `${key}_${today}`]);
  if (!quest || quest.completed) return null;

  const newProgress = Math.min(quest.progress + amount, quest.target);
  const completed = newProgress >= quest.target ? 1 : 0;
  runQuery('UPDATE quests SET progress = ?, completed = ?, completed_at = CASE WHEN ? THEN CURRENT_TIMESTAMP ELSE NULL END WHERE id = ?', 
    [newProgress, completed, completed, quest.id]);

  if (completed) {
    const qDef = dailyQuests.find(q => q.key === key);
    if (qDef) {
      return qDef.reward;
    }
  }
  return null;
}

