// ====== RANDOM UTILITIES ======

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function randomFloat(min, max) {
  return Math.random() * (max - min) + min;
}

function rollDice(sides = 6) {
  return randomInt(1, sides);
}

function chance(percentage) {
  return Math.random() * 100 < percentage;
}

function randomPick(array) {
  if (!array || array.length === 0) return null;
  return array[Math.floor(Math.random() * array.length)];
}

function weightedRandom(items, weights) {
  if (!items || items.length === 0) return null;
  const totalWeight = weights.reduce((a, b) => a + b, 0);
  let random = Math.random() * totalWeight;
  for (let i = 0; i < items.length; i++) {
    random -= weights[i];
    if (random <= 0) return items[i];
  }
  return items[items.length - 1];
}

function shuffleArray(array) {
  const arr = [...array];
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

// ====== GAME MECHANICS ======

function xpForLevel(level) {
  return config.battle.xpPerLevel * level * (1 + level * 0.1);
}

function calculateDamage(attack, defense, luck = 5, critChance = 5, critDamage = 150, dodgeChance = 5) {
  const base = Math.max(1, attack - defense * 0.4);
  const variance = randomFloat(0.85, 1.15);

  // Critical hit
  let isCrit = false;
  if (chance(critChance + luck * 0.2)) {
    isCrit = true;
  }

  // Dodge
  const isDodged = chance(dodgeChance);
  if (isDodged) {
    return { damage: 0, isCrit: false, isDodged: true };
  }

  let damage = Math.round(base * variance);
  if (isCrit) {
    damage = Math.round(damage * (critDamage / 100) * (1 + luck * 0.01));
  }

  // Luck adds variance
  damage += randomInt(-Math.floor(luck / 2), Math.floor(luck / 2));

  return { damage: Math.max(1, damage), isCrit, isDodged: false };
}

// ====== COOLDOWN SYSTEM ======

const cooldowns = new Map();

function checkCooldown(userId, action, seconds) {
  const key = `${userId}:${action}`;
  const now = Date.now();
  if (cooldowns.has(key)) {
    const expiresAt = cooldowns.get(key);
    if (now < expiresAt) {
      const remaining = Math.ceil((expiresAt - now) / 1000);
      return { onCooldown: true, remaining };
    }
  }
  cooldowns.set(key, now + seconds * 1000);
  return { onCooldown: false, remaining: 0 };
}

function formatTime(seconds) {
  if (seconds < 60) return `${seconds} ثانية`;
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  if (mins < 60) return `${mins} دقيقة و ${secs} ثانية`;
  const hours = Math.floor(mins / 60);
  const remainingMins = mins % 60;
  if (hours < 24) return `${hours} ساعة و ${remainingMins} دقيقة`;
  const days = Math.floor(hours / 24);
  const remainingHours = hours % 24;
  return `${days} يوم و ${remainingHours} ساعة`;
}

function formatNumber(num) {
  if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
  if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
  return num.toString();
}

function progressBar(current, max, length = 15) {
  const percentage = Math.min(1, current / max);
  const filled = Math.round(percentage * length);
  const empty = length - filled;
  return '█'.repeat(filled) + '░'.repeat(empty) + ` ${Math.round(percentage * 100)}%`;
}

