function doMining(level) {
  const available = miningLoot.filter(l => level >= l.minLevel);
  const weights = available.map(l => l.weight);
  const item = weightedRandom(available, weights);
  const quantity = randomInt(1, 3);
  const xpGain = item.expReward * quantity;
  const bonusGold = randomInt(5, 20 + level * 2);
  return { item, quantity, xpGain, bonusGold };
}

function doFishing(level) {
  const available = fishingLoot.filter(l => level >= l.minLevel);
  const weights = available.map(l => l.weight);
  const item = weightedRandom(available, weights);
  const quantity = 1;
  const xpGain = item.expReward;
  const bonusGold = randomInt(3, 15 + level);
  return { item, quantity, xpGain, bonusGold };
}

