// ====== PRESTIGE ======

function getPrestigeCost(level) {
  return Math.floor(1000 * Math.pow(1.5, level - 1));
}

function canPrestige(player) {
  return player.level >= 50 && player.gold >= getPrestigeCost(player.prestige + 1);
}

function doPrestige(player) {
  const p = player.prestige || 0;
  const cost = getPrestigeCost(p + 1);
  return {
    newPrestige: p + 1,
    cost,
    bonuses: {
      max_health: 50 * (p + 1),
      attack: 10 * (p + 1),
      defense: 5 * (p + 1),
      energy: 20 * (p + 1),
      luck: 2 * (p + 1),
    }
  };
}

// ====== GUILD WAR ======

function calculateGuildWar(attackerId, defenderId) {
  const atkMembers = require('./database/db').getGuildMembers(attackerId);
  const defMembers = require('./database/db').getGuildMembers(defenderId);

  const atkPower = atkMembers.reduce((sum, m) => sum + (m.contribution || 0), 0);
  const defPower = defMembers.reduce((sum, m) => sum + (m.contribution || 0), 0);

  const atkScore = atkPower + Math.random() * atkPower * 0.2;
  const defScore = defPower + Math.random() * defPower * 0.2;

  return {
    attackerWins: atkScore > defScore,
    attackerScore: Math.round(atkScore),
    defenderScore: Math.round(defScore),
    xpReward: Math.round((atkPower + defPower) * 0.1),
    goldReward: Math.round((atkPower + defPower) * 0.05)
  };
}

