module.exports = {
  data: new SlashCommandBuilder()
    .setName('quests')
    .setDescription('📋 عرض المهام اليومية والمهام المتاحة'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const quests = getQuests(interaction.user.id);

    if (quests.length === 0) {
      const embed = createBaseEmbed('📋 لا توجد مهام', 'لا توجد مهام متاحة اليوم. عد غداً!', 0x888888);
      return interaction.reply({ embeds: [embed] });
    }

    const { dailyQuests } = require('../../utils/helpers');

    let description = `**📋 مهام اليوم - ${interaction.user.username}**\n\n`;

    let completedCount = 0;
    let totalRewards = { gold: 0, xp: 0, essence: 0 };

    for (const quest of quests) {
      // Find the quest definition by matching the key prefix
      const questDef = dailyQuests.find(q => quest.quest_key.startsWith(q.key));
      if (!questDef) continue;

      const progress = quest.progress || 0;
      const target = quest.target || 1;
      const completed = quest.completed;

      if (completed) completedCount++;

      const bar = '█'.repeat(Math.round((progress / target) * 10)) + '░'.repeat(10 - Math.round((progress / target) * 10));
      const status = completed ? '✅ **مكتمل**' : `⏳ ${bar} ${progress}/${target}`;

      description += `**${questDef.name}**\n`;
      description += `📝 ${questDef.desc}\n`;
      description += `${status}\n`;
      if (completed && !quest.reward_claimed) {
        // Auto-claim
        const reward = questDef.reward;
        totalRewards.gold += reward.gold;
        totalRewards.xp += reward.xp;
        totalRewards.essence += reward.essence;
        description += `🎁 المكافأة: ${reward.gold}💰 ${reward.xp}📊 ${reward.essence}💎\n`;
        // Mark as claimed
        const { runQuery } = require('../../database/db');
        runQuery('UPDATE quests SET reward_claimed = 1 WHERE id = ?', [quest.id]);
      }
      description += '\n';
    }

    if (totalRewards.gold > 0 || totalRewards.xp > 0) {
      updatePlayer(interaction.user.id, {
        gold: player.gold + totalRewards.gold,
        xp: player.xp + totalRewards.xp,
        shadow_essence: (player.shadow_essence || 0) + totalRewards.essence
      });
      description += `\n🎉 **تم استلام المكافآت تلقائياً!**\n`;
      description += `💰 +${totalRewards.gold} ذهب | 📊 +${totalRewards.xp} XP | 💎 +${totalRewards.essence} جوهر\n`;
    }

    description += `\n**✅ المنجز: ${completedCount}/${quests.length}**`;

    const embed = createBaseEmbed(`📋 مهام ${interaction.user.username}`, description, 0x00aaff);
    await interaction.reply({ embeds: [embed] });
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle, EmbedBuilder } = require('discord.js');
