module.exports = {
  data: new SlashCommandBuilder()
    .setName('dungeon')
    .setDescription('🚪 ادخل زنزانة الظل - واجه الأعداء واهزم البوسات'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);

    const cd = checkCooldown(interaction.user.id, 'dungeon', 30);
    if (cd.onCooldown) {
      return interaction.reply({ content: `⏳ انتظر ${formatTime(cd.remaining)} قبل دخول الزنزانة مرة أخرى.`, ephemeral: true });
    }

    if (player.energy < 20) {
      return interaction.reply({ content: `❌ تحتاج 20 طاقة لدخول الزنزانة. طاقتك: ${player.energy}/${player.max_energy}`, ephemeral: true });
    }

    // Get or create dungeon progress
    let dungeon = getQuery('SELECT * FROM dungeon_progress WHERE user_id = ?', [interaction.user.id]);
    if (!dungeon) {
      runQuery('INSERT INTO dungeon_progress (user_id, health, max_hp) VALUES (?, ?, ?)', [interaction.user.id, player.health, player.max_health]);
      dungeon = getQuery('SELECT * FROM dungeon_progress WHERE user_id = ?', [interaction.user.id]);
    }

    const { getDungeonData } = require('../../database/db');
    const floors = getDungeonData();
    const currentFloor = Math.min(dungeon.current_floor || 1, floors.length);
    const floorData = floors[currentFloor - 1];

    // Deduct energy
    updatePlayer(interaction.user.id, { energy: player.energy - 20 });

    const embed = createBaseEmbed(`🚪 الزنزانة - الطابق ${currentFloor}`, 
      `**${floorData.name}**\n\n` +
      `**${interaction.user.username}** يدخل الزنزانة...\n\n` +
      `📍 الطابق: ${currentFloor}/10\n` +
      `❤️ صحتك: ${dungeon.health || player.health}/${player.max_health}\n` +
      `⚡ طاقتك: ${player.energy - 20}/${player.max_energy}\n\n` +
      `🎯 اختر مسارك:`,
      0x660000
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder().setCustomId('dungeon_fight').setLabel('⚔️ قتال').setStyle(ButtonStyle.Danger),
        new ButtonBuilder().setCustomId('dungeon_heal').setLabel('💊 شفاء (50💰)').setStyle(ButtonStyle.Success),
        new ButtonBuilder().setCustomId('dungeon_flee').setLabel('🏃 خروج').setStyle(ButtonStyle.Secondary)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    // Handle button interactions
    const filter = i => i.customId.startsWith('dungeon_') && i.user.id === interaction.user.id;
    const collector = interaction.channel.createMessageComponentCollector({ filter, time: 120000 });

    let currentHp = dungeon.health || player.health;
    let floor = currentFloor;
    let maxFloor = dungeon.max_floor || 1;
    let kills = 0;
    let goldEarned = 0;
    let xpEarned = 0;
    let essenceEarned = 0;
    let loot = [];

    collector.on('collect', async (i) => {
      if (i.customId === 'dungeon_flee') {
        const resultEmbed = createBaseEmbed('🏃 خروج من الزنزانة',
          `**نتائج الزنزانة:**\n\n` +
          `🏆 الطابق: ${floor}\n` +
          `💀 قتلى: ${kills}\n` +
          `💰 ذهب: ${goldEarned}\n` +
          `📊 XP: ${xpEarned}\n` +
          `💎 جوهر الظل: ${essenceEarned}\n` +
          (loot.length > 0 ? `🎁 الغنائم: ${loot.join(', ')}` : ''),
          0x888888
        );

        // Save progress
        runQuery('UPDATE dungeon_progress SET current_floor = ?, max_floor = ?, health = ?, last_run = CURRENT_TIMESTAMP WHERE user_id = ?',
          [floor, maxFloor, currentHp, interaction.user.id]);

        // Update leaderboard
        runQuery('INSERT OR REPLACE INTO dungeon_leaderboard (user_id, best_floor, total_runs, total_kills) VALUES (?, ?, COALESCE((SELECT total_runs FROM dungeon_leaderboard WHERE user_id = ?), 0) + 1, COALESCE((SELECT total_kills FROM dungeon_leaderboard WHERE user_id = ?), 0) + ?)',
          [interaction.user.id, Math.max(maxFloor, floor || 1), interaction.user.id, interaction.user.id, kills]);

        collector.stop();
        return i.update({ embeds: [resultEmbed], components: [] });
      }

      if (i.customId === 'dungeon_heal') {
        const playerData = getPlayer(interaction.user.id, interaction.user.username);
        if (playerData.gold < 50) {
          return i.reply({ content: '❌ ليس لديك 50 ذهب للشفاء!', ephemeral: true });
        }
        if (currentHp >= playerData.max_health) {
          return i.reply({ content: '✅ صحتك كاملة بالفعل!', ephemeral: true });
        }
        const healAmount = 30;
        currentHp = Math.min(currentHp + healAmount, playerData.max_health);
        updatePlayer(interaction.user.id, { gold: playerData.gold - 50 });

        const healEmbed = createBaseEmbed('💊 شفاء', `تم شفاء ${healAmount} نقطة صحة.\n❤️ صحتك الآن: ${currentHp}/${playerData.max_health}`, 0x00ff88);
        return i.update({ embeds: [healEmbed], components: [] }).catch(() => {});
      }

      if (i.customId === 'dungeon_fight') {
        const playerData = getPlayer(interaction.user.id, interaction.user.username);

        // Pick a random enemy from this floor
        const enemies = floorData.enemies || [];
        const boss = floorData.boss;

        // Boss fight every 3 floors, or final floor
        const isBossFight = floor % 3 === 0 || floor === 10;
        const enemy = isBossFight ? boss : (enemies.length > 0 ? enemies[Math.floor(Math.random() * enemies.length)] : { name: 'وحش ظل', hp: 50, atk: 10, def: 5, reward: 20 });

        if (!enemy) {
          return i.reply({ content: '❌ خطأ في تحميل بيانات العدو!', ephemeral: true });
        }

        // Fight simulation
        let enemyHp = enemy.hp + randomInt(-5, 10);
        let fightLog = `⚔️ معركة ضد **${enemy.name}**!\n\n`;

        let playerAttack = playerData.attack;
        let playerDefense = playerData.defense;

        // Multi-hit battle
        let turns = 0;
        while (enemyHp > 0 && currentHp > 0 && turns < 20) {
          turns++;

          // Player turn
          const atkResult = calculateDamage(playerAttack, enemy.defense || 0, playerData.luck || 5, playerData.crit_chance || 5, playerData.crit_damage || 150, playerData.dodge_chance || 5);
          if (atkResult.isDodged) {
            fightLog += `⏭️ ${enemy.name} تفادى هجومك!\n`;
          } else {
            enemyHp -= atkResult.damage;
            const elementMult = 1.0; // Could add elemental effects
            fightLog += `${atkResult.isCrit ? '💥 **ضربة حرجة!** ' : '⚔️ '}هاجمت ${enemy.name} بـ ${Math.round(atkResult.damage * elementMult)} ضرر\n`;
          }

          if (enemyHp <= 0) {
            fightLog += `\n✨ **انتصار!** قتلت ${enemy.name}\n`;
            break;
          }

          // Enemy turn
          const enemyAtk = calculateDamage(enemy.attack || enemy.atk, playerDefense);
          if (enemyAtk.isDodged) {
            fightLog += `💨 تفاديت هجوم ${enemy.name}!\n`;
          } else {
            currentHp -= enemyAtk.damage;
            fightLog += `💥 ${enemy.name} يضربك بـ ${enemyAtk.damage} ضرر\n`;
          }
        }

        if (currentHp <= 0) {
          fightLog += `\n💀 **هزمت!** لقد انهارت في المعركة...\n`;
