        .setDescription('الطلاق - إنهاء الزواج')),

  async execute(interaction) {
    const sub = interaction.options.getSubcommand();

    if (sub === 'propose') {
      const partner = interaction.options.getUser('partner');
      if (partner.id === interaction.user.id) return interaction.reply({ content: '❌ لا يمكنك الزواج من نفسك!', ephemeral: true });
      if (partner.bot) return interaction.reply({ content: '❌ لا يمكنك الزواج من بوت!', ephemeral: true });

      const existing = getMarriage(interaction.user.id);
      if (existing) return interaction.reply({ content: '❌ أنت متزوج بالفعل! استخدم `/marry divorce` أولاً.', ephemeral: true });

      const partnerMarriage = getMarriage(partner.id);
      if (partnerMarriage) return interaction.reply({ content: '❌ هذا الشخص متزوج بالفعل!', ephemeral: true });

      const player = getPlayer(interaction.user.id, interaction.user.username);

      // Ring check - must have a ring
      const inv = require('../../database/db').getInventory(interaction.user.id);
      const ring = inv.find(i => i.item_name === 'خاتم الزواج');
      if (!ring) {
        return interaction.reply({ content: '❌ تحتاج **خاتم زواج** لطلب الزواج! اصنعه باستخدام `/craft` (الوصفة: جوهر الظلام ×1 + دمعة العنقاء ×2 + بلورة الطاقة ×3)', ephemeral: true });
      }

      const embed = createBaseEmbed('💍 طلب زواج',
        `**${interaction.user.username}** يتقدم لخطبة **${partner.username}** 💕\n\n` +
        `❤️ هل تقبل به زوجاً/زوجةً لك في عالم الظل؟\n\n` +
        `على ${partner.username} الرد خلال 60 ثانية`,
        0xff69b4
      );

      const row = new ActionRowBuilder()
        .addComponents(
          new ButtonBuilder().setCustomId(`marry_accept:${interaction.user.id}`).setLabel('💍 أقبل').setStyle(ButtonStyle.Success),
          new ButtonBuilder().setCustomId(`marry_decline:${interaction.user.id}`).setLabel('❌ أرفض').setStyle(ButtonStyle.Danger)
        );

      await interaction.reply({ embeds: [embed], components: [row] });

      // Handle response
      const filter = i => i.customId.startsWith('marry_') && i.user.id === partner.id;
      try {
        const response = await interaction.channel.awaitMessageComponent({ filter, time: 60000 });

        if (response.customId === 'marry_decline') {
          const declineEmbed = createBaseEmbed('💔 رفض', `${partner.username} رفض الزواج من ${interaction.user.username}... 😢`, 0x888888);
          await response.update({ embeds: [declineEmbed], components: [] });
          return;
        }

        // Accept - remove ring and marry
        const { removeItem } = require('../../database/db');
        removeItem(ring.id);

        marryUsers(interaction.user.id, partner.id);
        checkAchievements(interaction.user.id);
        checkAchievements(partner.id);

        const acceptEmbed = createBaseEmbed('💑 **مبروك الزواج!** 🎉',
          `**${interaction.user.username}** ❤️ **${partner.username}**\n\n` +
          `أصبحتما متزوجين في عالم ممالك الظل!\n` +
          `بارك الله لكما وبارك عليكما وجمع بينكما في الخير 🤲\n\n` +
          `💍 تم استخدام خاتم الزواج`,
          0xff69b4
        );
        await response.update({ embeds: [acceptEmbed], components: [] });

      } catch (e) {
        const timeoutEmbed = createBaseEmbed('⏰ انتهى الوقت', `${partner.username} لم يرد على طلب الزواج.`, 0x888888);
        await interaction.editReply({ embeds: [timeoutEmbed], components: [] });
      }

    } else if (sub === 'accept') {
      const partner = interaction.options.getUser('partner');
      // This would be handled by the propose flow
      return interaction.reply({ content: '📌 استخدم عندما يرسل لك شخص طلب زواج عبر `/marry propose`.', ephemeral: true });

    } else if (sub === 'info') {
      const marriage = getMarriage(interaction.user.id);
      if (!marriage) return interaction.reply({ content: '❌ أنت غير متزوج! استخدم `/marry propose`.', ephemeral: true });

      const p1 = getQuery('SELECT username FROM players WHERE user_id = ?', [marriage.user1_id]);
      const p2 = getQuery('SELECT username FROM players WHERE user_id = ?', [marriage.user2_id]);
      const otherId = marriage.user1_id === interaction.user.id ? marriage.user2_id : marriage.user1_id;
      const otherName = marriage.user1_id === interaction.user.id ? p2?.username : p1?.username;

      const embed = createBaseEmbed('💑 الزواج', 
        `**${interaction.user.username}** 💕 **${otherName}**\n\n` +
        `📅 تزوجتما في: ${marriage.married_at}\n` +
        `💍 الزوج: <@${marriage.user1_id}>\n` +
        `💍 الزوجة: <@${marriage.user2_id}>`,
        0xff69b4
      );
      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'divorce') {
      const marriage = getMarriage(interaction.user.id);
      if (!marriage) return interaction.reply({ content: '❌ أنت غير متزوج!', ephemeral: true });

      const result = divorceUsers(interaction.user.id);
      if (!result) return interaction.reply({ content: '❌ حدث خطأ!', ephemeral: true });

      const embed = createBaseEmbed('💔 طلاق', `تم الطلاق. انفصلتما في عالم الظل... 😢`, 0x888888);
      await interaction.reply({ embeds: [embed] });
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, getShadows, addShadow, runQuery, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { randomInt, chance, generateShadowName, generateShadowType, generateRarity } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('fuse')
    .setDescription('🔮 دمج مخلوقين ظل للحصول على مخلوق أقوى')
    .addIntegerOption(o => o.setName('shadow1').setDescription('رقم المخلوق الأول').setRequired(true).setMinValue(1))
    .addIntegerOption(o => o.setName('shadow2').setDescription('رقم المخلوق الثاني').setRequired(true).setMinValue(1)),

  async execute(interaction) {
    const shadows = getShadows(interaction.user.id);

    if (shadows.length < 2) {
      return interaction.reply({ content: '❌ تحتاج مخلوقين ظل على الأقل للدمج!', ephemeral: true });
    }

    const idx1 = interaction.options.getInteger('shadow1') - 1;
    const idx2 = interaction.options.getInteger('shadow2') - 1;

    if (idx1 < 0 || idx1 >= shadows.length || idx2 < 0 || idx2 >= shadows.length) {
      return interaction.reply({ content: '❌ أرقام المخلوقات غير صحيحة!', ephemeral: true });
    }

    if (idx1 === idx2) {
      return interaction.reply({ content: '❌ لا يمكنك دمج مخلوق مع نفسه!', ephemeral: true });
    }

    const shadow1 = shadows[idx1];
    const shadow2 = shadows[idx2];

    const player = getPlayer(interaction.user.id, interaction.user.username);

    if (player.gold < 1000) {
      return interaction.reply({ content: '❌ تحتاج 1000 ذهب لعملية الدمج!', ephemeral: true });
    }

    const embed = createBaseEmbed('🔮 دمج الظلال',
      `**${shadow1.shadow_name}** (مستوى ${shadow1.level} - ${shadow1.rarity})\n` +
      `➕\n` +
      `**${shadow2.shadow_name}** (مستوى ${shadow2.level} - ${shadow2.rarity})\n\n` +
      `💰 التكلفة: 1000 ذهب\n` +
      `📊 فرصة النجاح: ${shadow1.rarity === 'خرافي' || shadow2.rarity === 'خرافي' ? 40 : shadow1.rarity === 'أسطوري' || shadow2.rarity === 'أسطوري' ? 55 : 75}%\n\n` +
      `هل تريد المتابعة؟`,
      0xaa44ff
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder().setCustomId('fuse_confirm').setLabel('🔮 دمج!').setStyle(ButtonStyle.Primary),
        new ButtonBuilder().setCustomId('fuse_cancel').setLabel('❌ إلغاء').setStyle(ButtonStyle.Danger)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    const filter = i => i.customId.startsWith('fuse_') && i.user.id === interaction.user.id;
    try {
      const response = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });

      if (response.customId === 'fuse_cancel') {
        return response.update({ embeds: [createBaseEmbed('❌ ألغي', 'تم إلغاء الدمج.', 0x888888)], components: [] });
      }

      // Process fusion
      updatePlayer(interaction.user.id, { gold: player.gold - 1000 });

      // Calculate result
      const successChance = shadow1.rarity === 'خرافي' || shadow2.rarity === 'خرافي' ? 40 : 
                            shadow1.rarity === 'أسطوري' || shadow2.rarity === 'أسطوري' ? 55 : 75;

      const levelAvg = Math.floor((shadow1.level + shadow2.level) / 2) + randomInt(1, 3);
      const rarityUp = chance(successChance);

      let resultRarity;
      if (rarityUp) {
        // Higher rarity
        const rarities = ['شائع', 'نادر', 'أسطوري', 'خرافي'];
        const maxRarity = Math.max(rarities.indexOf(shadow1.rarity), rarities.indexOf(shadow2.rarity));
        const newRarityIdx = Math.min(maxRarity + 1, rarities.length - 1);
        resultRarity = rarities[newRarityIdx];
      } else {
        // Lower or same
        const rarities = ['شائع', 'نادر', 'أسطوري', 'خرافي'];
        const maxRarity = Math.max(rarities.indexOf(shadow1.rarity), rarities.indexOf(shadow2.rarity));
        const newRarityIdx = Math.max(0, maxRarity - randomInt(0, 1));
        resultRarity = rarities[newRarityIdx];
      }

      const newName = generateShadowName();
      const newType = randomInt(0, 1) ? shadow1.shadow_type : shadow2.shadow_type;

      // Delete old shadows
      const { runQuery } = require('../../database/db');
      runQuery('DELETE FROM shadows WHERE id = ?', [shadow1.id]);
      runQuery('DELETE FROM shadows WHERE id = ?', [shadow2.id]);

      // Create new shadow
      const newShadowId = addShadow(interaction.user.id, newName, newType, resultRarity, levelAvg);

      // Record fusion
      runQuery('INSERT INTO shadow_fusions (user_id, result_shadow_id) VALUES (?, ?)', [interaction.user.id, newShadowId]);

      // Check achievements
      checkAchievements(interaction.user.id);

      const resultEmbed = createBaseEmbed(rarityUp ? '🎉 **دمج ناجح!**' : '⚠️ **دمج... مقبول**',
        `**${shadow1.shadow_name}** + **${shadow2.shadow_name}**\n\n` +
        `${rarityUp ? '✨ اندمجت الظلال لتخلق مخلوقاً أقوى!' : '🔀 اندمجت الظلال ولكن النتيجة ليست كما توقعت...'}\n\n` +
        `**⬇️ النتيجة ⬇️**\n` +
        `👾 **${newName}**\n` +
        `🔮 النوع: ${newType}\n` +
        `⭐ الندرة: ${resultRarity} ${rarityUp ? '⬆️' : '➡️'}\n` +
        `📊 المستوى: ${levelAvg}`,
        rarityUp ? 0xaa44ff : 0x888888
      );

      await response.update({ embeds: [resultEmbed], components: [] });

    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        await interaction.editReply({ embeds: [createBaseEmbed('⏰ انتهى الوقت', 'لم تختر شيئاً.', 0x888888)], components: [] }).catch(() => {});
      }
    }
  }
};

const { SlashCommandBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getSkills, addItem, runQuery } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { doMining, randomInt, checkCooldown, formatTime, chance } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('mine')
    .setDescription('⛏️ التعدين - احفر في مناجم الظل للحصول على المعادن النادرة'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const cd = checkCooldown(interaction.user.id, 'mine', 5);

    if (cd.onCooldown) {
      return interaction.reply({ content: `⏳ انتظر ${formatTime(cd.remaining)} قبل التعدين مرة أخرى.`, ephemeral: true });
    }

    if (player.energy < 5) {
      return interaction.reply({ content: `❌ تحتاج 5 طاقة للتعدين! طاقتك: ${player.energy}/${player.max_energy}`, ephemeral: true });
    }

    const skills = getSkills(interaction.user.id);
    const miningLevel = skills.mining_level || 1;

    updatePlayer(interaction.user.id, { energy: player.energy - 5 });

    const result = doMining(miningLevel);

    // XP gain for mining skill
    const newMiningXp = (skills.mining_xp || 0) + result.xpGain;
    const miningXpNeeded = miningLevel * 20;
    let newMiningLevel = miningLevel;

    if (newMiningXp >= miningXpNeeded) {
      newMiningLevel = miningLevel + 1;
      runQuery('UPDATE player_skills SET mining_level = ?, mining_xp = ? WHERE user_id = ?', [newMiningLevel, newMiningXp - miningXpNeeded, interaction.user.id]);
    } else {
      runQuery('UPDATE player_skills SET mining_xp = ? WHERE user_id = ?', [newMiningXp, interaction.user.id]);
    }

    // Add item to inventory
    addItem(interaction.user.id, 'material', result.item.name, result.item.rarity, result.quantity);

    // Bonus gold
    updatePlayer(interaction.user.id, { gold: player.gold + result.bonusGold });

    // XP for player
    const xpGain = Math.floor(result.xpGain * 0.5);
    updatePlayer(interaction.user.id, { xp: player.xp + xpGain });

    const rarityEmojis = { 'شائع': '⬜', 'نادر': '🟦', 'أسطوري': '🟨', 'خرافي': '🟪' };

    const embed = createBaseEmbed('⛏️ تعدين',
      `🔨 تضرب بفأسك في صخر الظل...\n\n` +
      `🎁 وجدت: ${rarityEmojis[result.item.rarity] || '⬜'} **${result.item.name}** ×${result.quantity}\n` +
      `💰 ذهب إضافي: +${result.bonusGold}\n` +
      `📊 خبرة تعدين: +${result.xpGain} (المستوى ${newMiningLevel})\n\n` +
      `⚡ طاقتك: ${player.energy - 5}/${player.max_energy}`,
      result.item.rarity === 'نادر' ? 0x00aaff : result.item.rarity === 'أسطوري' ? 0xffaa00 : result.item.rarity === 'خرافي' ? 0xff44ff : 0x888888
    );

    if (newMiningLevel > miningLevel) {
      embed.addFields({ name: '🎉 ارتفاع مستوى التعدين!', value: `تهانينا! وصلت إلى مستوى تعدين ${newMiningLevel}!`, inline: false });
    }

    await interaction.reply({ embeds: [embed] });
  }
};

