const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, buyLotteryTicket, getLotteryStats, drawLottery, allQuery, runQuery, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { randomInt, chance, checkCooldown, formatTime } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('gamble')
    .setDescription('🎲 ألعاب الحظ - يانصيب، زهر، عملة')
    .addSubcommand(sub =>
      sub.setName('dice')
        .setDescription('🎲 لعب الزهر - اربح ذهباً')
        .addIntegerOption(o => o.setName('bet').setDescription('الرهان').setRequired(true).setMinValue(10)))
    .addSubcommand(sub =>
      sub.setName('coinflip')
        .setDescription('🪙 قلب عملة - مضاعفة الرهان')
        .addStringOption(o => o.setName('choice').setDescription('اختر').setRequired(true).addChoices({ name: 'وجه', value: 'وجه' }, { name: 'كتابة', value: 'كتابة' }))
        .addIntegerOption(o => o.setName('bet').setDescription('الرهان').setRequired(true).setMinValue(10)))
    .addSubcommand(sub =>
      sub.setName('lottery')
        .setDescription('🍀 شراء تذكرة يانصيب - اربح الجائزة الكبرى!')
        .addIntegerOption(o => o.setName('tickets').setDescription('عدد التذاكر (1-10)').setRequired(false).setMinValue(1).setMaxValue(10))),

  async execute(interaction) {
    const sub = interaction.options.getSubcommand();

    if (sub === 'dice') {
      const bet = interaction.options.getInteger('bet');
      const player = getPlayer(interaction.user.id, interaction.user.username);

      if (player.gold < bet) return interaction.reply({ content: `❌ ليس لديك ${bet} ذهب!`, ephemeral: true });

      const playerRoll = randomInt(1, 6) + randomInt(1, 6);
      const botRoll = randomInt(1, 6) + randomInt(1, 6);

      let won = false;
      let winnings = 0;

      if (playerRoll > botRoll) {
        won = true;
        winnings = Math.floor(bet * 1.8);
        updatePlayer(interaction.user.id, { gold: player.gold + winnings - bet });
      } else if (playerRoll === botRoll) {
        winnings = bet; // Draw - return bet
      } else {
        updatePlayer(interaction.user.id, { gold: player.gold - bet });
      }

      const embed = createBaseEmbed('🎲 زهر الظل',
        `🎲 **${interaction.user.username}** : ${playerRoll}\n` +
        `🎲 **الخصم** : ${botRoll}\n\n` +
        `${won ? `🎉 **ربحت!** +${winnings - bet}💰` : playerRoll === botRoll ? '🤝 **تعادل!** استرداد رهانك.' : '💔 **خسرت!**'} ` +
        `\n💰 رصيدك: ${won ? player.gold + winnings - bet : playerRoll === botRoll ? player.gold : player.gold - bet}`,
        won ? 0x00ff88 : playerRoll === botRoll ? 0xffaa00 : 0xff4444
      );

      await interaction.reply({ embeds: [embed] });

    } else if (sub === 'coinflip') {
      const choice = interaction.options.getString('choice');
      const bet = interaction.options.getInteger('bet');
      const player = getPlayer(interaction.user.id, interaction.user.username);

      if (player.gold < bet) return interaction.reply({ content: `❌ ليس لديك ${bet} ذهب!`, ephemeral: true });

      const result = chance(50) ? 'وجه' : 'كتابة';
      const won = result === choice;

      if (won) {
        const winnings = Math.floor(bet * 1.9);
        updatePlayer(interaction.user.id, { gold: player.gold + winnings - bet });
        const embed = createBaseEmbed('🪙 قلب عملة',
          `🪙 سقطت: **${result}**\n` +
          `🎯 اخترت: **${choice}**\n\n` +
          `🎉 **ربحت!** +${winnings - bet}💰\n` +
          `💰 رصيدك: ${player.gold + winnings - bet}`,
          0x00ff88
        );
        await interaction.reply({ embeds: [embed] });
      } else {
        updatePlayer(interaction.user.id, { gold: player.gold - bet });
        const embed = createBaseEmbed('🪙 قلب عملة',
          `🪙 سقطت: **${result}**\n` +
          `🎯 اخترت: **${choice}**\n\n` +
          `💔 **خسرت!** -${bet}💰\n` +
          `💰 رصيدك: ${player.gold - bet}`,
          0xff4444
        );
        await interaction.reply({ embeds: [embed] });
      }

    } else if (sub === 'lottery') {
      const tickets = interaction.options.getInteger('tickets') || 1;
      const player = getPlayer(interaction.user.id, interaction.user.username);
      const cost = tickets * 500;

      if (player.gold < cost) return interaction.reply({ content: `❌ تحتاج ${cost} ذهب لشراء ${tickets} تذاكر!`, ephemeral: true });

      updatePlayer(interaction.user.id, { gold: player.gold - cost });

      for (let i = 0; i < tickets; i++) {
        buyLotteryTicket(interaction.user.id);
      }

      const stats = getLotteryStats();
      const totalTickets = stats.total || 0;

      const embed = createBaseEmbed('🍀 يانصيب الظل',
        `اشتريت **${tickets}** تذكرة يانصيب!\n\n` +
        `📊 إجمالي التذاكر: ${totalTickets}\n` +
        `🏆 الجائزة الكبرى: ${(totalTickets * 500 * 0.8).toLocaleString()} 💰\n\n` +
        `🍀 حظاً موفقاً! سيتم سحب اليانصيب قريباً.`,
        0xffd700
      );

      await interaction.reply({ embeds: [embed] });
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle } = require('discord.js');
const { getPlayer, updatePlayer, runQuery, checkAchievements } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { canPrestige, doPrestige, getPrestigeCost } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('prestige')
    .setDescription('🌀 نظام التمرير - ابدأ من جديد بمكافآت دائمة وقوية'),

  async execute(interaction) {
    const player = getPlayer(interaction.user.id, interaction.user.username);
    const currentPrestige = player.prestige || 0;

    if (!canPrestige(player)) {
      const cost = getPrestigeCost(currentPrestige + 1);
      return interaction.reply({
        content: `❌ شروط التمرير:\n` +
          `📊 المستوى: ${player.level}/50\n` +
          `💰 الذهب: ${player.gold.toLocaleString()}/${cost.toLocaleString()}\n` +
          `🔄 التمرير الحالي: ${currentPrestige}`,
        ephemeral: true
      });
    }

    const result = doPrestige(player);

    const embed = createBaseEmbed('🌀 **تمرير المستوى!**',
      `**${interaction.user.username}** يمرر مستواه!\n\n` +
      `🔄 من التمرير ${currentPrestige} → ${result.newPrestige}\n` +
      `💰 التكلفة: ${result.cost.toLocaleString()} ذهب\n\n` +
      `**المكافآت الدائمة:**\n` +
      `❤️ صحة: +${result.bonuses.max_health}\n` +
      `⚔️ هجوم: +${result.bonuses.attack}\n` +
      `🛡️ دفاع: +${result.bonuses.defense}\n` +
      `⚡ طاقة: +${result.bonuses.energy}\n` +
      `🍀 حظ: +${result.bonuses.luck}\n\n` +
      `سيتم إعادة تعيين مستواك إلى 1، ذهبك إلى 500، لكن مخلوقات الظل ومخزونك سيبقى!`,
      0xaa44ff
    );

    const row = new ActionRowBuilder()
      .addComponents(
        new ButtonBuilder().setCustomId('prestige_confirm').setLabel('🌀 تمرير!').setStyle(ButtonStyle.Danger),
        new ButtonBuilder().setCustomId('prestige_cancel').setLabel('❌ إلغاء').setStyle(ButtonStyle.Secondary)
      );

    await interaction.reply({ embeds: [embed], components: [row] });

    const filter = i => i.customId.startsWith('prestige_') && i.user.id === interaction.user.id;
    try {
      const response = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });

      if (response.customId === 'prestige_cancel') {
        return response.update({ embeds: [createBaseEmbed('❌ ألغي', 'تم إلغاء التمرير.', 0x888888)], components: [] });
      }

      // Apply prestige
      updatePlayer(interaction.user.id, {
        prestige: result.newPrestige,
        level: 1,
        xp: 0,
        gold: 500,
        health: result.bonuses.max_health + 100,
        max_health: result.bonuses.max_health + 100,
        attack: result.bonuses.attack + 10,
        defense: result.bonuses.defense + 5,
        max_energy: result.bonuses.energy + 100,
        energy: result.bonuses.energy + 100,
        luck: (player.luck || 5) + result.bonuses.luck,
        gold: player.gold - result.cost
      });

      checkAchievements(interaction.user.id);

      const successEmbed = createBaseEmbed('🌀 **تم التمرير بنجاح!**',
        `**${interaction.user.username}** الآن في التمرير ${result.newPrestige}! 🎉\n\n` +
        `لقد أصبحت أقوى مما مضى! ابدأ رحلتك من جديد بمكافآت دائمة!`,
        0xaa44ff
      );

      await response.update({ embeds: [successEmbed], components: [] });

    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        await interaction.editReply({ content: '⏰ انتهى الوقت.', components: [] }).catch(() => {});
      }
    }
  }
};

const { SlashCommandBuilder, ActionRowBuilder, StringSelectMenuBuilder, StringSelectMenuOptionBuilder } = require('discord.js');
const { getPlayer, updatePlayer, getSkills, runQuery } = require('../../database/db');
const { createBaseEmbed } = require('../../utils/embeds');
const { specializations, specializationBonuses } = require('../../utils/helpers');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('specialize')
    .setDescription('⚡ اختر تخصصك - مقاتل، ساحر، صياد، أو زعيم'),

  async execute(interaction) {
    const skills = getSkills(interaction.user.id);
    const currentSpec = skills.specialization || 'مقاتل';

    const select = new StringSelectMenuBuilder()
      .setCustomId('spec_select')
      .setPlaceholder('🎯 اختر تخصصك...')
      .addOptions(
        Object.entries(specializations).map(([key, val]) =>
          new StringSelectMenuOptionBuilder()
            .setLabel(key === currentSpec ? `${key} (حالياً)` : key)
            .setValue(key)
            .setDescription(val.desc)
            .setEmoji(key === 'مقاتل' ? '⚔️' : key === 'ساحر' ? '🔮' : key === 'صياد' ? '🏹' : '👑')
        )
      );

    const row = new ActionRowBuilder().addComponents(select);

    let desc = '🎯 **اختر تخصصك بحكمة!**\nالتخصص يمنح مكافآت دائمة.\n\n';
    for (const [key, val] of Object.entries(specializations)) {
      const bonus = specializationBonuses[key];
      const isCurrent = key === currentSpec;
      desc += `${isCurrent ? '✅' : '▪️'} **${key}** - ${val.desc}\n`;
      desc += `   ❤️ +${bonus.max_health} | ⚔️ +${bonus.attack} | 🛡️ +${bonus.defense}`;
      if (bonus.crit_chance) desc += ` | 💥 +${bonus.crit_chance}% crit`;
      if (bonus.dodge_chance) desc += ` | 💨 +${bonus.dodge_chance}% dodge`;
      if (bonus.luck) desc += ` | 🍀 +${bonus.luck} luck`;
      desc += '\n\n';
    }

    const embed = createBaseEmbed('⚡ التخصصات', desc, 0x00aaff);

    await interaction.reply({ embeds: [embed], components: [row] });

    const filter = i => i.customId === 'spec_select' && i.user.id === interaction.user.id;
    try {
      const selection = await interaction.channel.awaitMessageComponent({ filter, time: 30000 });
      const chosen = selection.values[0];

      if (chosen === currentSpec) {
        return selection.update({ embeds: [createBaseEmbed('⚡ تخصصك الحالي', `أنت بالفعل ${currentSpec}!`, 0x888888)], components: [] });
      }

      const bonus = specializationBonuses[chosen];

      // Apply spec bonuses (replace old bonuses)
      const player = getPlayer(interaction.user.id, interaction.user.username);
      const oldBonus = specializationBonuses[currentSpec];

      const newStats = {
        max_health: Math.max(100, player.max_health - (oldBonus?.max_health || 0) + (bonus.max_health || 0)),
        health: Math.max(100, player.health - (oldBonus?.max_health || 0) + (bonus.max_health || 0)),
        attack: Math.max(5, player.attack - (oldBonus?.attack || 0) + (bonus.attack || 0)),
        defense: Math.max(1, player.defense - (oldBonus?.defense || 0) + (bonus.defense || 0)),
        crit_chance: Math.max(0, (player.crit_chance || 5) - (oldBonus?.crit_chance || 0) + (bonus.crit_chance || 0)),
        dodge_chance: Math.max(0, (player.dodge_chance || 5) - (oldBonus?.dodge_chance || 0) + (bonus.dodge_chance || 0)),
        luck: Math.max(0, (player.luck || 5) - (oldBonus?.luck || 0) + (bonus.luck || 0)),
      };

      updatePlayer(interaction.user.id, newStats);
      runQuery('UPDATE player_skills SET specialization = ? WHERE user_id = ?', [chosen, interaction.user.id]);

      const resultEmbed = createBaseEmbed('✅ تم تغيير التخصص!',
        `**${currentSpec}** → **${chosen}**\n\n` +
        `🔄 تم تطبيق مكافآت التخصص الجديد!`,
        0x00ff88
      );

      await selection.update({ embeds: [resultEmbed], components: [] });

    } catch (e) {
      if (e.code !== 'INTERACTION_COLLECTOR_ERROR') {
        // ignore timeout
      }
    }
  }
};

