const db = require('./database/db');
db.initDatabase().then(() => {
  console.log('✓ DB initialized');

  // Test player
  const p = db.getPlayer('test1', 'TestUser1');
  console.log('✓ Player:', p.username, 'Gold:', p.gold);

  // Test achievements
  const ach = db.checkAchievements('test1');
  console.log('✓ New achievements:', ach.length);

  // Test quests
  const q = db.getQuests('test1');
  console.log('✓ Quests loaded:', q.length);

  // Test skills
  const sk = db.getSkills('test1');
  console.log('✓ Skills:', sk.specialization, 'Mining:', sk.mining_level);

  // Test dungeon
  const floors = db.getDungeonFloors();
  console.log('✓ Dungeon floors:', floors.length);

  // Test market
  db.createListing('test1', 'Test Sword', 'weapon', 'نادر', 1, '{\"attack\":10}', 500);
  const listings = db.getMarketListings();
  console.log('✓ Market listings:', listings.length);

  // Test friends
  db.sendFriendRequest('test1', 'friend1');
  db.sendFriendRequest('test1', 'friend2');
  db.acceptFriendRequest('friend1', 'test1');
  const friends = db.getFriends('test1');
  console.log('✓ Friends:', friends.length);

  // Test marriage
  db.marryUsers('test1', 'spouse1');
  const marriage = db.getMarriage('test1');
  console.log('✓ Married:', marriage ? 'yes' : 'no');

  // Test lottery
  const ticket = db.buyLotteryTicket('test1');
  console.log('✓ Lottery ticket:', ticket);

  // Test boosters
  db.activateBooster('test1', 'xp', 1.5, 30);
  const boosters = db.getActiveBoosters('test1');
  console.log('✓ Active boosters:', boosters.length);

  // Test leaderboards
  const lb = db.getLeaderboard('level');
  console.log('✓ Leaderboard:', lb.length, 'entries');

  const lb2 = db.getLeaderboard('dungeon');
  console.log('✓ Dungeon LB:', lb2.length, 'entries');

  console.log('\n🎉 ALL TESTS PASSED!');
  process.exit(0);
}).catch(err => {
  console.error('✗', err);
  process.exit(1);
});
